INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (68, 'pt-br', 'help_search', ' reordenando e desativando links do menu objetivo desativar links de menu ou alterar a ordem e a hierarquia dos links do menu passos no menu administrativo gerenciar  navegue ate estrutura  menus clique em editar menu no menu que deseja editar arraste os links do menu para uma nova ordem ou marque desmarque ativado para ativar ou desativar links de menu clique em salvar para salvar suas alteracoes  ', 1773421629);
