INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (63, 'pt-br', 'help_search', ' verificando o status da traducao da interface objetivo verifique o status atual das traducoes de interface e veja se ha alguma atualizacao disponivel passos no menu administrativo gerenciar  navegue ate configuracao   regiao e idioma  idiomas olhe para a coluna de traducao de interface na tabela de idiomas para encontrar a porcentagem de texto da interface do usuario que foi traduzida para cada idioma no menu administrativo gerenciar  navegue ate relatorios   atualizacoes de traducao disponiveis  esse relatorio so estara disponivel se o modulo de update status estiver instalado opcionalmente clique em verificar manualmente para atualizar o relatorio veja o relatorio para saber se algum idioma tem atualizacoes de traducao que voce pode baixar  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (10, 'pt-br', 'help_search', ' exportando a configuracao completa do site objetivo crie e baixe um arquivo contendo toda a configuracao do seu site exportado como arquivos yaml consulte gerenciamento e implantacao de configuracao para obter mais informacoes sobre configuracao passos no menu administrativo gerenciar  navegue ate configuracao   desenvolvimento     sincronizacao de configuracao   exportar  clique em exportar e salve o arquivo  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (26, 'pt-br', 'help_search', ' gerenciando estrutura de conteudo que tipos de dados um site tem  existem quatro tipos principais de dados conteudo e a informacao texto imagens etc destinadas a serem exibidas aos visitantes do site configuracao sao dados que definem como o conteudo e exibido algumas configuracoes como etiquetas de campo tambem podem ser visiveis para os visitantes do site estado sao dados temporarios sobre o estado do seu site como a ultima vez que o sistema cron empregos correu a sessao e um subconjunto de informacoes do estado relacionadas as interacoes dos usuarios com o site como cookies de sites e se estao ou nao conectados o que e uma entidade de conteudo  uma entidade de conteudo  ou mais comumente  entidade  e um item de dados de conteudo que pode consistir em texto marcacao html imagens arquivos anexados e outros dados as entidades de conteudo sao agrupadas em tipos de entidade  que tem finalidades diferentes e sao exibidas de maneiras muito diferentes no site a maioria dos tipos de entidade tambem e dividida em subtipos de entidade  que sao divisoes dentro de um tipo de entidade para permitir variacoes menores na forma como as entidades sao usadas e exibidas por exemplo o tipo de entidade de item de conteudo que armazena conteudo no nivel da pagina e dividido em subtipos de tipo de conteudo  o tipo de entidade de bloco de conteudo tem tipos de bloco  mas o tipo de entidade usuario  para informacoes de perfil de usuario nao tem subtipos o que e um campo  dentro de itens de entidade os dados sao armazenados em campos individuais cada um dos quais contem um tipo de dados como texto formatado ou simples imagens ou outros arquivos ou datas os campos podem ser adicionados por um administrador em subtipos de entidade de modo que todos os itens da entidade de um determinado subtipo de entidade tenham a mesma colecao de campos disponiveis e eles possam ser de valor unico ou de valor multiplo quando voce cria ou edita itens da entidade voce esta especificando os valores para os campos no item da entidade o que e um campo referenciado  um campo de referencia e um campo que armazena uma relacao entre uma entidade e uma ou mais entidades que podem pertencer ao mesmo tipo de entidade ou diferente por exemplo um campo de referencia de conteudo em um tipo de conteudo armazena uma relacao entre um item de conteudo e um ou mais itens de conteudo quais tipos de campos estao disponiveis  os seguintes tipos de campo sao fornecidos pelo sistema principal e modulos principais muitos mais sao fornecidos por modulos contribuidos booleano numero fornecido pelo sistema principal armazena valores verdadeiros falsos e numeros comentario fornecido pelo modulo comment permite que usuarios adicionem comentarios em uma entidade data timestamp modulo datetime armazena datas e horas faixa de data modulo datetime range armazena periodos de data hora com um inicio e um fim email core system armazena enderecos de email link modulo link armazena urls e textos de links lista modulo options armazena valores escolhidos a partir de listas predefinidas onde os valores podem ser numeros ou texto veja a secao abaixo para mais informacoes sobre os campos da lista referencia sistema central armazena referencias de entidades veja a secao acima telefone modulo telephone armazena numeros de telefones texto modulo text armazena textos formatados e nao formados veja a secao abaixo para mais informacoes sobre campos de texto quais configuracoes estao disponiveis para os tipos de campo lista  os campos de lista associam chaves predefinidas ou codigos de valor com rotulos que o usuario ve por exemplo voce pode definir um campo de lista que mostra ao usuario os nomes de varios locais enquanto nos bastidores um codigo de localizacao e armazenado no banco de dados cada tipo de campo de lista corresponde a um tipo de chave armazenada por exemplo um campo list inteiro  armazena inteiros enquanto o campo lista texto  armazena strings de texto uma vez escolhido o tipo de campo a configuracao principal para um campo de lista e a lista de valores permitido  que associa as teclas com os rotulos quais tipos de campos de texto estao disponiveis  existem varios tipos de campos de texto com diferentes caracteristicas campos de texto podem ser simples ou formatados  campos de texto simples nao contem html enquanto os campos formatados podem conter html e sao processados atraves de filtros de texto  estes sao fornecidos pelo modulo filter do core se voce tiver esse modulo habilitado consulte o topico relacionado com filtros abaixo para obter mais informacoes campos de texto tambem podem ser de comprimento regular com um limite de 255 caracteres ou longos  com um limite de caracteres muito grande e campos de texto longos formatados podem incluir um atributo de resumo  todas as possiveis combinacoes dessas caracteristicas existem como tipos de campo de texto por exemplo  texto simples  e texto formatado longo com resumo  sao dois exemplos de tipos de campo de texto o que e um formatador  um formatador e uma maneira de exibir um campo a maioria dos tipos de campo oferecem varios tipos de formatadores e a maioria dos formatadores possuem configuracoes que definem ainda mais como o campo e exibido tambem e possivel ocultar completamente um campo da exibicao e voce tem a opcao de mostrar ou ocultar o rotulo do campo quando ele e exibido o que e um widget  um widget e uma maneira de editar um campo alguns tipos de campo como campos de linha unica de texto simples tem apenas um widget disponivel neste caso um campo de entrada de texto de linha unica outros tipos de campo oferecem opcoes para o widget por exemplo os campos de lista de um valor unico podem usar um widget de botao select ou radio para edicao muitos tipos de widget tem configuracoes que definem ainda mais como o campo pode ser editado gerenciando a visao geral da estrutura de conteudo alem dos modulos de campo listados na secao anterior existem modulos adicionais do core que voce pode usar para gerenciar sua estrutura de conteudo the core node comment content block custom menu links user file image media and taxonomy modules all provide content entity types o modulo core field ui fornece uma interface de usuario para gerenciamento de campos e seu display em entidades o modulo core layout builder fornece uma interface de usuario mais flexivel para configurar a exibicao de entidades os modulos do core filter rdf responsive image e path fornecem opcoes de configuracoes e exibicao para entidades e campos dependendo dos modulos do nucleo e de contribuicao que voce instalou em seu site os topicos relacionados abaixo e outros topicos listados na pagina de ajuda principal consulte ajuda ajudarao voce com tarefas relacionadas a estrutura de conteudo recursos adicionais conceito tipos de dados guia do usuario do drupal  planejando seu site guia do usuario do drupal  conceito campos de referencia guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (19, 'pt-br', 'help_search', ' gerenciamento e implantacao de configuracao o que e o sistema de configuracao  o sistema de configuracao fornece para administradores a capacidade de personalizar o site e de mover e sincronizar as alteracoes de configuracao entre os sites de desenvolvimento e o site em producao ele faz isso de 2 maneiras fornecendo armazenamento para configuracao fornecer um processo no qual as alteracoes de configuracao podem ser importadas e exportadas entre instancias do mesmo site por exemplo de dev para staging para live  o que sao dados de configuracao  dados de configuracao descrevem configuracoes que definem como seu site se comporta ou e exibido por exemplo quando um administrador do site atualiza as configuracoes usando um formulario administrativo essas configuracoes sao armazenadas como dados de configuracao os dados de configuracao descrevem configuracoes tao simples quanto um nome de site e tao complexas quanto uma view ou estilo de imagem quais tipos de configuracao existem  configuracao ativa a configuracao ativa e a configuracao de trabalho atual de um site o armazenamento da configuracao ativa e definido pelo site e reside no banco de dados por padrao configuracao simples um item de configuracao simples e um grupo de configuracoes como as configuracoes de um modulo ou tema cada item de configuracao simples tem sua propria estrutura unica configuracao de entidades as entidades de configuracao sao itens de configuracao definidos pelo usuario agrupados por tipo como views estilos de imagem e tipos de conteudo cada entidade de configuracao dentro de um tipo tem uma estrutura semelhante configuracao padrao a configuracao padrao pode ser definida por um modulo tema ou perfil de instalacao em seus diretorios config install ou config optional  a configuracao e fornecida em arquivos yaml extensao de arquivo yml yaml e um padrao de serializacao de dados legivel por humanos que e usado pelo software principal para varios propositos uma vez que a configuracao padrao foi importada para a configuracao ativa do site atraves da instalacao da extensao essa configuracao e de propriedade do site nao da extensao isso significa que futuras atualizacoes da extensao nao substituirao a configuracao ativa do site para essa extensao o que e sincronizacao de configuracao  sincronizacao de configuracao e o processo de exportacao e importacao de configuracao para manter a configuracao sincronizada entre diferentes versoes de um site por exemplo entre um site de desenvolvimento e o site em producao cada site tem identificador exclusivo tambem chamado de uuid  que identifica o site para o sistema em qualquer instancia do site desde que as instancias do site tenham sido reproduzidas como clones clonagem e quando a base de codigo e o banco de dados sao copiados para criar uma nova instancia do site quando as instancias do site sao clonadas uma instancia dev do site tem o mesmo uuid que a instancia live quando as instancias do site compartilham o mesmo uuid a configuracao pode ser exportada de uma instancia para outra a seguinte lista contem termos e conceitos relacionados a sincronizacao de configuracao configuracao exportada quando a configuracao e exportada a configuracao ativa e exportada como um conjunto de arquivos no formato yaml ao usar a interface administrativa do usuario para configuracao de sincronizacao  a configuracao pode ser exportada como um arquivo de exportacao completo ou um arquivo de um unico item este arquivo pode entao ser importado para a instancia do site de destino configuracao importada configuracao importada e a configuracao que foi exportada a partir de outra instancia do site a fonte e agora esta sendo importada em outra instancia do site o destino atualizando assim sua configuracao ativa para corresponder ao conjunto de dados de configuracao importado diretorio de sincronizacao de configuracao o local do diretorio de sincronizacao de configuracao esta definido no arquivo settingsphp  quando a configuracao e exportada a configuracao ativa e exportada e descrita em arquivos yaml que sao armazenados no diretorio de sincronizacao de configuracao apos a primeira exportacao o sistema compara a configuracao ativa do site com os dados de configuracao no diretorio de sincronizacao e somente exportara os itens de configuracao ativos que sao diferentes de suas contrapartes no diretorio de sincronizacao gerenciando a visao geral de configuracao as tarefas de gerenciamento de configuracao como exportar ou importar configuracao e sincronizacao de configuracao podem ser feitas atraves da interface administrativa fornecida pelo modulo configuration manager do core ou por uma ferramenta cli commandline interface para definir um caminho de diretorio de sincronizacao de configuracao que nao seja o valor padrao e necessario acesso de leitura gravacao as configuracoes do arquivo settingsphp  a maioria dos modulos e temas tambem fornecem formas de configuracao para atualizar a configuracao que eles fornecem veja os topicos relacionados listados abaixo para tarefas especificas recursos adicionais gerenciamento de configuracao fluxo de trabalho usando drush conceito tipos de dados guia do usuario do drupal  conceito sites de desenvolvimento guia do usuario do drupal  criando um site de desenvolvimento guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (47, 'pt-br', 'help_search', ' modificando as permissoes de um papel objetivo modifique as permissoes para um papel existente passos no menu administrativo gerenciar  navegue ate pessoas   permissoes  revise as permissoes para o papel prestando especial atencao as permissoes marcadas com aviso de somente para papeis confiaveis esta permissao tem implicacoes de seguranca na linha da permissao e da coluna do papel marque ou desmarque permissoes para este papel clique salvar permissoes   ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (2, 'pt-br', 'help_search', ' colocando um bloco objetivo coloque um bloco em uma regiao de um tema passos no menu administrativo gerenciar  navegue ate estrutura  layout de bloco clique no nome do tema onde deseja colocar o bloco opcionalmente clique em demonstrar regioes de bloco para ver as regioes do tema encontre a regiao onde deseja colocar o bloco e clique em colocar bloco nessa regiao uma caixa de dialogo sera mostrada encontre o bloco que deseja colocar e clique em colocar bloco  uma caixa de dialogo de configurar bloco sera mostrada configure o bloco e clique em salvar bloco  consulte configurando um bloco previamente colocado para obter detalhes de configuracao  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (74, 'pt-br', 'help_search', ' configurando apelidos para urls o que e uma url  url e a abreviacao de uniform resource locator que e o endereco da pagina na web e o nome pelo qual um navegador identifica uma pagina para mostrala no exemplo visitenos em exemplocom   https exemplocom seria a url para a pagina inicial do seu site usuarios usam urls para localizar conteudo na web o que e um caminho  um caminho e a exclusiva ultima parte da url para uma funcao especifica ou peca de conteudo por exemplo para uma pagina cuja url completa e https exemplocom node 7  o caminho e node 7  aqui estao alguns exemplos de caminhos que voce pode encontrar em seu site node 7 campinho para um item de conteudo especifico taxonomy term 6 caminho para uma pagina de um termo de taxonomia user 3 caminho para uma pagina de perfil de usuario o que e um apelido  o software core permite que voce forneca urls mais compreensiveis para paginas em seu site que sao chamadas de apelidos  por exemplo se voce tiver uma pagina sobre nos com o caminho node 7  voce pode configurar um apelido sobre para que seus visitantes vejam como https wwwexemplocom sobre  visao geral das configuracoes de caminhos apelidos e urls o modulo path do core fornece a funcionalidade de apelidos de url o modulo contribuido pathauto permite configurar apelidos de url gerados automaticamente para itens de conteudo e outras paginas veja os topicos relacionados listados abaixo para tarefas especificas recursos adicionais conceito caminhos apelidos e urls guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (54, 'pt-br', 'help_search', ' usando links contextuais objetivo use links contextuais para acessar tarefas administrativas sem navegar no menu administrativo o que sao links contextuais  links contextuais dao aos usuarios com a permissao usar links contextuais acesso rapido a tarefas administrativas relacionadas a areas de paginas nao administrativas por exemplo se uma pagina em seu site exibe um bloco o bloco teria um link contextual que permitiria aos usuarios com permissao configurar o bloco se o bloco contiver um menu ou uma view ele tambem teria um link contextual para editar os links do menu ou da view clicar em um link contextual leva voce diretamente para a pagina administrativa relacionada sem precisar navegar pelo sistema de menu administrativo passos certifiquese que o modulo contextual links esta instalado e que voce tenha um papel com a permissao de usar links contextuais  opcionalmente certifiquese que um modulo de barra de ferramentas esteja instalado seja o modulo toolbar do core ou um modulo contribuido substituto visite uma pagina nao administrativa em seu site como a pagina inicial localize um bloco ou outra area na pagina que deseja editar ou configurar torne visivel o botao de links contextuais colocando o mouse sobre aquela area na pagina na maioria dos temas este botao parece um lapis e e colocado no canto superior direito da area da pagina canto superior esquerdo para idiomas da direita para a esquerda e colocar o mouse sobre a area tambem ira delinear temporariamente a area afetada alternativamente clique no botao de alternar links contextuais na extremidade direita da barra de ferramentas extremidade esquerda para idiomas da direita para a esquerda que tornara visiveis na pagina todos os botoes de link contextuais ate que ele seja clicado novamente enquanto o botao de links contextuais para a area de interesse e visivel clique no botao para exibir a lista de links para essa area clique em um link na lista para visitar a pagina administrativa correspondente complete sua tarefa administrativa e salve suas configuracoes ou cancele a acao voce deve ser redirecionado para a pagina de onde comecou  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (29, 'pt-br', 'help_search', ' ampliando e modificando funcionalidades do seu site o que e um modulo  um modulo e um conjunto de arquivos php javascript e ou css que amplia os recursos do site e adiciona funcionalidade um conjunto de modulos core e distribuido como parte do download do software principal modulos adicionais contribuidos podem ser baixados separadamente na pagina download estender no drupalorg  o que e um modulo experimental  um modulo experimental e um modulo que ainda esta em desenvolvimento e ainda nao esta estavel o uso de modulos experimentais em producao nao e recomendado o que esta instalando e desinstalando  instalar um modulo do core ou um modulo contribuido baixado significa ligalo para que voce possa usar seus recursos e funcionalidade desinstalar significa desligalo e remover toda a sua configuracao um modulo nao pode ser desinstalado se outro modulo instalado depender dele ou se voce tiver criado conteudo em seu site usando o modulo voce precisara excluir o conteudo e desinstalar modulos dependentes primeiro ampliando a visao geral consulte os topicos relacionados listados abaixo para ajuda na execucao de tarefas relacionadas a extensao de funcionalidades do seu site recursos adicionais conceito modulos guia do usuario do drupal  estendendo e personalizando seu site guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (71, 'pt-br', 'help_search', ' gerenciando conteudo o que e um item de conteudo  um item de conteudo e um tipo de entidade de conteudo para conteudo em nivel de pagina que pode ter campos que armazenam texto marcacao html imagens arquivos anexados e outros dados consulte gerenciando estrutura de conteudo para saber mais sobre entidades e campos de conteudo o que e um tipo de conteudo  os itens de conteudo sao divididos em tipos de conteudo  que sao os subtipos da entidade para o tipo de entidade de item de conteudo cada tipo de conteudo tem seus proprios campos e configuracoes de exibicao por exemplo voce pode configurar tipos de conteudo para paginas artigos receitas eventos e entradas de blog em seu site visao geral do gerenciamento de conteudo o modulo node do core permite definir tipos de conteudo e adicionar e editar itens de conteudo o modulo field ui do core permite que voce anexe campos a cada tipo de conteudo e gerencie o formulario de edicao e exibicao para cada tipo de conteudo veja os topicos relacionados listados abaixo para tarefas especificas muitos outros modulos do core e contribuidos e perfis de instalacao fornecem tipos de conteudo predefinidos modificam a estrutura de permissao para itens de conteudo e fornecem outras funcionalidades  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (4, 'pt-br', 'help_search', ' configurando um bloco previamente colocado objetivo configure as configuracoes de um bloco que foi colocado anteriormente em uma regiao de um tema passos no menu administrativo gerenciar  navegue ate estrutura   layout de bloco  clique no nome do tema que contem o bloco opcionalmente clique em demonstrar regioes de bloco para ver as regioes do tema se voce quiser apenas alterar a regiao onde um bloco esta localizado ou a ordem dos blocos dentro de uma regiao arraste blocos para as posicoes desejadas e clique em salvar blocos  se voce quiser alterar configuracoes adicionais encontre a regiao onde o bloco que deseja atualizar esta localizado atualmente e clique em configurar na linha da descricao do bloco editar as configuracoes do bloco as configuracoes disponiveis variam dependendo do modulo que fornece o bloco mas para todos os blocos voce pode alterar  titulo do bloco  o cabecalho para o bloco no seu site para alguns blocos voce precisara marcar a caixa sobrescrever titulo para inserir um titulo titulo do display  marque esta caixa se quiser que o titulo seja exibido visibilidade  adiciona condicoes para quando o bloco deve ser exibido regiao  altera a regiao no tema em que o bloco e exibido clique em salvar bloco   ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (34, 'pt-br', 'help_search', ' ativando e desativando o modo de manutencao objetivo coloque seu site no modo de manutencao para realizar operacoes de manutencao e em seguida retorne ao modo normal quando terminar o que e o modo de manutencao  quando seu site estiver no modo de manutencao a maioria dos visitantes do site vera uma simples pagina com mensagem do modo de manutencao em vez de usar todas as funcionalidades do site usuarios com a permissao usar o site no modo de manutencao que ja estao autenticados poderao usar o site completo e a pagina de autenticacao em  user tambem estara acessivel para qualquer um passos no menu administrativo gerenciar  navegue ate configuracao   desenvolvimento   modo de manutencao  marque colocar o site no modo de manutencao e opcionalmente troque a mensagem para exibir quando estiver no modo de manutencao e clique em salvar configuracao  seu site estara em modo de manutencao realize suas operacoes de manutencao no menu administrativo gerenciar  navegue ate configuracao   desenvolvimento   modo de manutencao  desmarque colocar o site no modo de manutencao e clique em salvar configuracao  seu site estara de volta no modo normal de operacao limpa o cache do site veja limpando o cache do site para instrucoes  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (70, 'pt-br', 'help_search', ' criando um item de conteudo objetivo crie e publique um item de conteudo consulte gerenciando conteudo para saber mais sobre tipos de conteudo e itens de conteudo quem pode criar conteudo  usuarios com permissao de acessar a pagina de visao geral de conteudo podem visitar a pagina conteudo conforme descrito neste topico cada tipo de conteudo tem suas proprias permissoes de criacao por exemplo para criar conteudo do tipo artigo um usuario precisaria da permissao criar novo conteudo alem disso os usuarios com as permissoes de pular o controle de acesso de conteudo ou administrar conteudo podem criar itens de conteudo de todos os tipos alguns modulos contribuidos alteram a estrutura de permissoes para criacao de conteudo passos no menu administrativo gerenciar  navegue ate conteudo  clique em adicionar conteudo  se houver mais de um tipo de conteudo definido em seu site que voce tem permissao para criar clique no nome do tipo de conteudo que deseja criar no formulario de edicao de conteudo digite o titulo do seu conteudo que sera exibido como o titulo da pagina quando o item de conteudo for exibido em uma pagina e tambem como o rotulo do item de conteudo em telas de administracao preencha os outros campos mostrados no formulario de edicao para este tipo de conteudo especifico deixe marcado o campo publicado para publicar o conteudo imediatamente ou desmarqueo para tornalo despublicado conteudo despublicado geralmente nao e mostrado para usuarios nao administrativos do site opcionalmente clique em previsualizar para previsualizar o conteudo clique em salvar  voce vera o conteudo em uma pagina recursos adicionais gerenciamento basico de paginas guia do usuario do drupal  criando um item de conteudo guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (80, 'pt-br', 'help_search', ' editando um display de view existente objetivo editar um display de view existente para modificar quais dados sao exibidos ou como sao exibidos passos se voce ainda nao estiver editando sua exibicao no menu administrativo gerenciar  navegue ate estrutura  views  localize a vista que voce deseja editar e clique no link editar  em displays  clique no display que deseja editar encontre a secao cujas configuracoes deseja alterar como criterios de formato ou de filtro  veja gerenciamento listagens de conteudo views para obter mais informacoes em secoes contendo listas como campos e criterios de filtros  para modificar ou excluir um item existente clique no nome do item para adicionar um novo item clique em adicionar na lista dropdown para alterar a ordem dos itens clique em reorganizar na lista dropdown para secoes que contem configuracoes individuais como titulo e formato  muitas vezes ha dois links para cada configuracao o primeiro link mostra o valor atual clique nesse link para alterar o valor se houver um segundo link chamado configuracoes  clique nesse link para alterar os detalhes das configuracoes por exemplo se o seu formato e mostrado atualmente como lista naoformatada  clique em lista naoformatada para trocar para um formato de grade ou tabela  clique em configuracoes ao lado do tipo de formato para alterar as configuracoes do formato escolhido quando voce terminar de alterar todas as configuracoes verifique se o display esta correto clicando em atualizar previsualizacao  retorne para editar as configuracoes se necessario quando voce tiver verificado o display clique em salvar  alternativamente se voce cometeu erros e deseja descartar suas alteracoes clique em cancelar  recursos adicionais criando listagens com views guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (67, 'pt-br', 'help_search', ' adicionando um link em um menu objetivo adiciona um link em um menu observe que voce tambem pode adicionar um link em um menu na pagina de edicao de conteudo se as configuracoes do menu foram configuradas para o tipo de conteudo passos no menu administrativo gerenciar  navegue ate estrutura  menus localize o menu desejado e clique em adicionar link na lista operacoes  digite o titulo do link de menu a ser exibido digite o link  um dos seguintes um caminho interno como  node add uma url externa completa comece a digitar o titulo de um item de conteudo e selecioneo quando o titulo completo aparecer  nolink  para mostrar o titulo do link de menu como texto plano sem um link link  front  para a pagina inicial do seu site certifiquese de que habilitado esta marcado se nao o link do menu nao sera exibido opcionalmente digite uma descricao que sera exibida quando um usuario pairar sobre o link opcionalmente marque mostrar como expandido para mostrar automaticamente as os filhos deste link se houverem quando ele for mostrado opcionalmente selecione o link pai se este link de menu deve ser filho de outro link de menu clique em salvar  voce sera redirecionado para a pagina adicionar link para adicionar outro link no menu administrativo gerenciar  navegue ate estrutura  menus localize o menu que voce acabou de adicionar um link e clique em editar na lista operacoes  verifique se a ordem dos links esta correta se nao estiver arraste os links do menu ate que a ordem esteja correta e clique em salvar   ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (83, 'pt-br', 'help_search', ' criando uma nova view objetivo crie uma nova view para listar conteudo ou outros itens em seu site passos no menu administrativo gerenciar  navegue ate estrutura   views  clique em adicionar view  no campo nome da view  digite um nome para a view que e como ela sera listada na interface administrativa em configuracoes da view   mostrar  selecione o tipo de dados base a serem exibidos em sua view isso nao pode ser alterado depois opcionalmente selecione ou digite as configuracoes de filtragem classificacao e exibicao de pagina bloco estes podem ser adicionados ou alterados mais tarde clique em salvar e editar  sua view sera criada editea seguindo as etapas nos topicos relacionados abaixo  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (35, 'pt-br', 'help_search', ' instalando um tema e definindo temas padrao objetivo instale um tema principal ou um tema contribuido que ja tenha sido baixado escolha os temas padrao para usar no site e em paginas administrativas passos no menu administrativo gerenciar  navegue ate aparencia  localize os temas que deseja usar como tema padrao do site e para paginas administrativas para cada um desses temas se o tema estiver na secao temas desinstalados  clique no link instalar para instalar o tema aguarde a instalacao do tema as traducoes podem ser baixadas voce deve ser redirecionado para a pagina aparencia  localize o tema que deseja que seja o tema padrao que agora deve estar na secao temas instalados  se ele ainda nao estiver rotulado como tema padrao  clique no link definir como padrao  na parte inferior da pagina selecione o tema da area de administracao que deseja usar em paginas administrativas clique em salvar caso tenha selecionado um novo tema se voce alterou o tema padrao do seu site visite a pagina inicial do site ou outra pagina na parte naoadministracao do seu site e verifique se o site esta usando o novo tema se voce alterou o tema da administracao verifique se o novo tema e usado em paginas administrativas  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (45, 'pt-br', 'help_search', ' criando uma conta de usuario objetivo criar uma nova conta de usuario passos no menu administrativo gerenciar  navegue ate pessoas  clique adicionar usuario  informe o endereco de email   nome de usuario e senha  duas vezes para o novo usuario verifique se os papeis selecionados para o novo usuario estao corretos se voce quiser que o novo usuario receba uma mensagem de email notificandoo da nova conta marque notificar o usuario de nova conta  opcionalmente altere outras configuracoes no formulario clique em criar nova conta  voce sera deixado a pagina adicionar usuario  repita estes passos se voce precisa criar mais contas de usuario  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (6, 'pt-br', 'help_search', ' criando um bloco de conteudo objetivo crie um bloco de conteudo que pode ser colocado posteriormente no site passos no menu administrativo gerenciar  navegue ate conteudo  abra a guia blocos de conteudo clique em adicionar bloco de conteudo  se voce tiver mais de um tipo de bloco definido em seu site clique no nome do tipo que deseja criar digite a descricao do seu bloco para ser exibido para administradores e o corpo de texto para o seu bloco clique salvar   ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (39, 'pt-br', 'help_search', ' configurando respostas de erro incluindo paginas 403404 objetivo configure seu site para responder aos erros do site adequadamente incluindo respostas de paginas 403 e 404 o que sao as respostas 403 e 404  quando um usuario visita uma pagina web o servidor web envia um codigo de resposta alem do conteudo da pagina uma resposta normal sem erro tem codigo 200 se a pagina nao existir no site o codigo de resposta e 404 se a pagina existir mas o usuario nao estiver autorizado a visitar a pagina o codigo de resposta e 403 o software principal fornece respostas padrao para codigos 403 e 404 mas se preferir voce pode criar suas proprias paginas para cada um quais outros erros podem ocorrer  em algumas situacoes seu site pode gerar mensagens de erro estes podem ser devido a erros do usuario como inserir valores invalidos em um formulario ou configuracao incorreta erros de tempo de execucao php ou bugs de software alguns erros podem resultar em uma tela branca da morte  uma resposta totalmente em branco na pagina web erros menos drasticos gerarao mensagens de erro voce pode configurar o que acontece quando uma mensagem de erro e gerada passos se desejar crie paginas que serao usadas para respostas 403 e 404 observe as urls para estas paginas no menu administrativo gerenciar  navegue ate configuracao   sistema   configuracao basica do site  na secao paginas de erro  digite a url das paginas 403404 comecando apos a url da pagina inicial do site por exemplo se a url do seu site e https examplecom e sua pagina 404 e https examplecom notfound  voce deve digitar  notfound  clique em salvar configuracao  voce deve ver uma mensagem indicando que as configuracoes foram salvas no menu administrativo gerenciar  navegue ate configuracao   desenvolvimento   registros e erros  para um site em producao selecione nenhum nas mensagens de erro para exibir  para um site que esteja em desenvolvimento selecione uma das outras opcoes para que voce esteja ciente dos erros que o site esta gerando clique em salvar configuracao  voce deve ver uma mensagem indicando que as configuracoes foram salvas  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (36, 'pt-br', 'help_search', ' desinstalando um tema nao utilizado objetivo desinstala um tema que foi instalado anteriormente mas nao esta mais sendo usado no site passos no menu administrativo gerenciar  navegue ate aparencia  localize o tema que deseja desinstalar na secao temas instalados  clique no link desinstalar para desinstalar o tema se nao houver um link desinstalar  o tema nao podera ser desinstalado porque esta sendo usado como o tema padrao do site usado como o tema administracao ou e o tema base para outro tema instalado  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (69, 'pt-br', 'help_search', ' criando um tipo de conteudo objetivo crie um novo tipo de conteudo consulte gerenciando conteudo para saber mais sobre tipos de conteudo quem pode criar um tipo de conteudo  usuarios com permissao de administrar tipos de conteudo  normalmente administradores podem criar novos tipos de conteudo passos no menu administrativo gerenciar  navegue ate estrutura    commenttypeslink  clique em adicionar tipo de conteudo no campo rotulo  digite um nome para o tipo de comentario que e como ele sera listado na interface administrativa opcionalmente digite uma descricao para o tipo de conteudo voce tambem pode ajustar algumas das configuracoes na secao de abas verticais da pagina de edicao clique em salvar e gerenciar campos  seu tipo de conteudo sera criado e supondo que voce tenha o modulo core field ui instalado voce sera levado para a pagina gerenciar campos para o tipo de conteudo se voce nao tiver o modulo core field ui instalado o botao mostrara salvar  se voce tiver o modulo core field ui instalado siga as etapas nos topicos relacionados para adicionar campos ao novo tipo de conteudo configure o formulario de edicao e configure a exibicao recursos adicionais adicionando um tipo de conteudo guia do usuario do drupal  configurando a estrutura de conteudo guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (31, 'pt-br', 'help_search', ' configurando paginas de busca objetivo configure uma ou mais paginas de busca passos no menu administrativo gerenciar  navegue ate configuracao   pesquisa e metadados   paginas de busca  role ate a secao paginas de busca  voce vera uma lista das paginas de busca ja configuradas em seu site para configurar uma pagina de busca existente clique em editar  ou para adicionar uma nova pagina de busca selecione o tipo de pagina de busca e clique em adicionar pagina de busca  digite o rotulo desejado e o caminho da url para a pagina de busca para paginas de busca de conteudo  selecione o nivel de influencia desejado na classificacao de resultados de busca dos fatores de classificacao de conteudo disponiveis clique em salvar  voce sera redirecionado para a pagina paginas de busca  verifique se a pagina de busca correta esta listada como padrao na coluna status  se nao clique em definir como padrao na lista operacoes para a pagina de busca correta opcionalmente desabilite ou exclua quaisquer paginas de busca que voce nao deseja ter disponivel no site a desabilitacao e temporaria enquanto a exclusao e permanente siga os passos de gerenciando o indice de busca para garantir que o indice de pesquisa seja atualizado  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (60, 'pt-br', 'help_search', ' adicionando um idioma objetivo adicione um idioma ao seu site passos no menu administrativo gerenciar  navegue ate configuracao   regiao e idioma  idiomas clique em adicionar idioma  se o idioma estiver na lista de nomes do idioma  selecioneo e clique em adicionar idioma  se o seu idioma nao estiver na lista selecione idioma personalizado  e digite o codigo de idioma   nome do idioma e direcao para o idioma clique em adicionar idioma personalizado  wait for the translation system to be updated also if you have the core update status module installed and translations are available for your language wait for translations to be downloaded you should be returned to the languages page when this completes  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (14, 'pt-br', 'help_search', ' usando a interface administrativa quais componentes da interface administrativa estao disponiveis  os seguintes componentes de interface administrativa sao fornecidos pelo software principal e seus modulos alguns modulos contribuidos oferecem funcionalidade adicional recursos de acessibilidade para permitir que todos os usuarios executem tarefas administrativas consulte acessibilidade da interface administrativa para mais informacoes um sistema de menu que voce pode navegar para encontrar paginas para tarefas administrativas o modulo toolbar do core exibe este menu no lado superior ou esquerdo da pagina lado direito em idiomas da direita para a esquerda ha tambem modulos contribuidos que substituem o modulo toolbar do core com recursos adicionais como o modulo admin toolbar  o modulo shortcuts do core melhora a barra de ferramentas com uma lista configuravel de links para tarefas comumente usadas se voce instalar o modulo do core contextual links paginas nao administrativas conterao links que levam as tarefas administrativas relacionadas edicao inloco ou rapida  a edicao inloco da configuracao e fornecida pelo modulo principal settings tray consulte usando a edicao de configuracoes em linha rapida para mais informacoes o modulo help do core exibe topicos de ajuda e fornece um bloco de ajuda que pode ser colocado em paginas administrativas para fornecer uma visao geral de sua funcionalidade o que sao secoes do menu administrativo  o menu administrativo que voce pode navegar visitando  admin em seu site ou usando uma barra de ferramentas administrativa tem as seguintes secoes algumas podem nao estar disponiveis dependendo de quais modulos estao atualmente instalados em seu site e suas permissoes  conteudo  encontrar gerenciar e criar novas paginas gerenciar comentarios e arquivos estrutura  posicione e edite blocos configure tipos e campos de conteudo configure menus administre taxonomia e configure alguns modulos contribuidos aparencia  alternar entre temas instalar temas e atualizar temas existentes estender  atualizar instalar e desinstalar modulos configuracao  configura as configuracoes para varias funcionalidades do site incluindo alguns modulos contribuidos pessoas  gerenciar contas de usuarios e permissoes relatorios  exibir informacoes sobre seguranca do site atualizacoes necessarias e atividades do site ajuda  obtenha ajuda no uso da interface administrativa visao geral da interface de administracao instale os modulos core mencionados acima para utilizar o aspecto correspondente da interface administrativa veja topicos relacionados listados abaixo para mais detalhes sobre alguns aspectos da interface administrativa  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (66, 'pt-br', 'help_search', ' configurar as opcoes do menu para um tipo de conteudo objetivo para um tipo de conteudo existente configure os menus disponiveis que serao mostrados como opcoes em telas de edicao de conteudo links para itens de conteudo desse tipo podem ser adicionados nesses menus durante a edicao passos no menu administrativo gerenciar  navegue ate estrutura  tipos de conteudo localize o tipo de conteudo que deseja configurar e clique em editar na lista operacoes  nas configuracoes de menu  marque os menus que deseja que estejam disponiveis quando editar um item de conteudo desse tipo opcionalmente selecione o item pai padrao para adicionar links para itens de conteudo abaixo de um local padrao na estrutura do menu clique salvar   ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (22, 'pt-br', 'help_search', ' gerenciando menus o que e um menu  um menu e uma colecao de links de menu usados para navegar em um site menus e links de menu podem ser fornecidos por modulos ou administradores de sites gerenciando previsualizacao de menus o modulo menu ui do core fornece uma interface de usuario para gerenciar menus incluindo a criacao de novos menus reordenacao de links de menu e desativacao de links fornecidos por modulos ele tambem fornece a capacidade para adicionar links no menu para itens de conteudo quando estes estao sendo editados se configurado no tipo de conteudo o modulo custom menu links do core fornece a capacidade de adicionar links personalizados aos menus cada menu pode ser exibido colocando um bloco em uma regiao do tema alguns temas tambem podem exibir um menu fora do sistema de blocos veja os topicos relacionados listados abaixo para tarefas especificas recursos adicionais conceito menu guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (59, 'pt-br', 'help_search', ' adding an image style objetivo adicione um novo estilo de imagem que pode ser usado para processar e exibir imagens consulte gerenciamento de midia para uma visao geral dos estilos de imagem passos no menu administrativo gerenciar  navegue ate configuracao   midia   estilos de imagens  clique em adicionar estilo de imagem  digite um nome descritivo de estilo de imagem e clique em criar novo estilo  em efeito  escolha um efeito para aplicar e clique em adicionar  configure o efeito na proxima pagina a maioria dos efeitos requer alguma configuracao adicional depois de adicionados por exemplo para o efeito crop  digite a largura e altura para cortar a imagem e escolha o ponto ancora clique em adicionar efeito  repita as duas etapas anteriores ate que todos os efeitos tenham sido adicionados arraste para mudar a ordem dos efeitos em seguida clique em salvar para salvar a nova ordem o estilo de imagem agora pode ser usado para formatar um campo contendo uma imagem em seus layouts ou exibicoes de campo tradicionais tambem pode ser usado como parte de um estilo de imagem responsivo veja os topicos relacionados abaixo para mais informacoes  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (13, 'pt-br', 'help_search', ' gerenciando filtros e formatos de texto objetivo configure formatos de texto no site o que sao filtros de texto e formatos de texto  um filtro de texto e uma etapa de processamento que pode ser aplicada ao texto seja para transformalo de alguma forma como converter urls no texto em links html ou para se defender contra entradas potencialmente perigosas dos usuarios do site um formato de texto e uma sequencia ordenada de filtros de texto os filtros de texto sao fornecidos por modulos formatos de texto sao gerenciados pelo modulo filter do core campos de texto que possuem a palavra formatado no nome do tipo de campo como em texto formatado   usam formatos de texto usuarios escolhem o formato de texto quando estao editando o texto no campo e quando o texto e mostrado no site ele e processado pelo formato de texto escolhido administradores podem configurar formatos de texto e atribuir permissoes para quem pode usar cada formato se o modulo text editor do core estiver habilitado administradores tambem poderao associar editores visuais a formatos de texto quais filtros de texto estao disponiveis  alguns dos filtros de texto mais usados sao limitar tags html permitidas e corrigir html incorreto limita quais tags html podem ser usadas util tanto para a seguranca do site quanto para forcar o design do site converte quebra de linhas em html quebras de linha na fonte html sao exibidas como espacos horizontais este filtro converte quebras de linha em tags de paragrafo e de quebra de linha html converte urls em links pega urls no texto e as transforma em links html restringir imagens para este site para formatos de texto que permitem tags html de imagem restringe as imagens para urls internas deste site passos no menu administrativo gerenciar  navegue ate configuracao criacao de conteudo   formatos e editores de texto  se voce nao tiver o modulo principal do editor de texto instalado o link do menu e o titulo da pagina serao formatos de texto  clique em configurar para configurar um formato de texto existente ou em  adicionar formato de texto para criar um novo formato de texto digite o nome desejado para o formato de texto verifique os papeis que podem usar este formato de texto algumas tags html permitem que usuarios incorporem links ou scripts maliciosos em texto para garantir seguranca usuarios anonimos e nao confiaveis so devem ter acesso a formatos de texto que os restrinjam ao uso de texto simples ou a um conjunto seguro de tags html a configuracao inadequada do formato de texto e um risco a seguranca se o modulo text editor do core esta instalado consulte o topico relacionado para conectar um editor de texto a este formato de texto em filtros ativos  verifique os filtros de texto que deseja utilizar em ordem de filtro de processamento  arraste os filtros para a ordem correta escolha a ordem cuidadosamente por exemplo se voce tem um filtro cujo resultado e adicionar uma tag html especifica ao texto ele deve ser executado apos um filtro que restringe tags html para evitar a exclusao das novas tags adicionadas pelo primeiro filtro nas configuracoes de filtro  verifique e ajuste as configuracoes de cada filtro ativo que possua opcoes de configuracao clique em salvar configuracao  que ira redirecionalo para a pagina formatos texto e editores  repita essas etapas se voce tiver formatos de texto adicionais para configurar  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (65, 'pt-br', 'help_search', ' criando um menu objetivo crie um novo menu passos no menu administrativo gerenciar  navegue ate estrutura  menus clique em adicionar menu  digite o titulo do menu usado como o titulo padrao do bloco se o menu for exibido como um bloco se desejar tambem edite o nome de maquina do menu que e por padrao derivado do titulo digite um resumo administrativo que sera exibido na pagina menus  se o seu site tem mais de um idioma escolha o idioma para o menu clique em salvar  voce estara na pagina de edicao do menu pronto para adicionar links ao menu se o modulo core custom menu links estiver instalado ver topicos relacionados para outras tarefas  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (16, 'pt-br', 'help_search', ' executando e configurando o cron objetivo configure seu sistema para que o cron seja executado automaticamente o que sao tarefas agendadas  para garantir que seu site e seus modulos continuem funcionando bem um grupo de operacoes administrativas deve ser executado periodicamente essas operacoes sao chamadas de tarefas de cron e executar estas tarefas e conhecido como executar o cron  dependendo da frequencia com que o conteudo e atualizado em seu site pode ser que precise executar o cron com uma frequencia que varia de hora em hora a semanal para manter seu site funcionando bem quais opcoes estao disponiveis para executar o cron  se o modulo do core automated cron esta instalado seu site pode executar o cron periodicamente em uma frequencia que voce pode configurar voce pode configurar uma tarefa em seu servidor web visitando a url do cron  que e exclusiva do seu site periodicamente voce tambem pode executar o cron manualmente mas esta nao e a maneira recomendada de se certificar de que e executado periodicamente passos no menu administrativo gerenciar  navegue ate configuracao   sistema   agendador de tarefas  veja o ultimo tempo de execucao na pagina se voce quiser executar agora o cron clique em executar cron e espere que o cron termine se voce tiver uma maneira para configurar tarefas em seu servidor web copie o link onde ele diz para executar o cron de fora do site va para  configure uma tarefa para visitar essa url no cronograma desejado de cron como uma vez por hora ou uma vez por semana em servidores semelhantes ao linux voce pode usar o comando wget para visitar uma url se voce configurar uma tarefa externa voce deve desinstalar o modulo automated cron se voce nao esta configurando uma tarefa externa e tiver o modulo automated cron do core instalado selecione um cronograma para execucoes automatizadas do cron nas configuracoes do cron   rodar agendador de tarefas a cada  clique em salvar configuracoes  recursos adicionais conceito cron guia do usuario do drupal  configurando tarefas de manutencao do cron guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (62, 'pt-br', 'help_search', ' traduzindo textos da interface do usuario objetivo traduza as strings de texto da interface do usuario do ingles para um idioma naoingles configurado em seu site passos no menu administrativo gerenciar  navegue ate configuracao   regiao e idioma  traducao da interface do usuario usando os filtros procure por uma string ou conjunto de strings que voce deseja traduzir certifiquese de selecionar o idioma de traducao correto se voce tiver mais de um idioma naoingles em seu site digite novas traducoes e clique em salvar traducoes  repita essas etapas ate que todo o texto desejado da interface do usuario seja traduzido para todos os idiomas do seu site  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (75, 'pt-br', 'help_search', ' editando um apelido de url objetivo altere um apelido de url existente para corrigir o caminho ou o valor do apelido veja configurando apelidos para urls para mais informacoes sobre apelidos quem pode gerenciar apelidos de urls  usuarios com as permissoes de administrar urls alternativas podem editar apelidos passos no menu administrativo gerenciar  navegue ate configuracoes   busca e metadados   urls alternativas  uma lista de todos os apelidos do site sera apresentada clique em editar no botao suspenso no apelido que deseja alterar faca as alteracoes necessarias e clique em salvar  voce sera redirecionado para a pagina da lista de apelidos de url note que voce tambem pode adicionar novos apelidos a partir desta pagina para qualquer caminho de seu site  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (73, 'pt-br', 'help_search', ' criando um apelido de url para um item de conteudo objetivo dar a uma pagina de item de conteudo um apelido de url humano ou seofriendly voce pode seguir passos semelhantes para criar um apelido para uma pagina de termo de taxonomia veja configurando apelidos para urls para mais informacoes sobre apelidos quem pode criar apelidos de urls  usuarios com permissao de criar e editar urls alternativas podem criar apelidos para seguir os passos deste topico voce tambem precisara de permissao para editar o item de conteudo passos localize e abra o formulario de edicao de conteudo do item de conteudo ou crie um novo item de conteudo veja topicos relacionados sobre a criacao e edicao de conteudo em apelido de url no formulario de edicao digite o apelido desejado por exemplo sobrenos certifiquese de que o apelido comeca com um caractere clique salvar  verifique se a pagina pode ser visitada com o novo apelido por exemplo https exemplocom sobrenos  recursos adicionais criando um item de conteudo guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (44, 'pt-br', 'help_search', ' modificando ou excluindo uma conta de usuario objetivo atualizando ou excluindo um usuario existente passos no menu administrativo gerenciar  navegue ate pessoas  digite todo ou parte do nome do usuario ou endereco de email da conta de usuario que deseja atualizar ou excluir e clique em filtro  uma pequena lista de contas de usuario incluindo a conta de interesse deve ser mostrada na tabela se nao modifique o texto do filtro ate que voce possa encontrar a conta de interesse clique em editar na area de operacoes da conta de interesse para excluir a conta do usuario role ate a parte inferior e clique em cancelar conta  selecione o que deve acontecer com o conteudo do usuario na proxima tela e clique em cancelar conta  para atualizar a conta do usuario digite novos valores no formulario e clique em salvar   ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (11, 'pt-br', 'help_search', ' exportando um unico item de configuracao objetivo exporte um unico item de configuracao para um arquivo consulte gerenciamento e implantacao de configuracao para obter mais informacoes sobre a configuracao passos no menu administrativo gerenciar  navegue ate configuracao   desenvolvimento   sincronizacao de configuracao   exportar   item unico  selecione o tipo de configuracao que deseja exportar e selecione o nome de configuracao especifico para exportar use seu navegador para copiar o texto na caixa marcada aqui esta sua configuracao na area de transferencia cole o texto copiado em um editor de texto simples em seu computador ou outro dispositivo e salveo usando o nome do arquivo sugerido abaixo da caixa de texto  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (42, 'pt-br', 'help_search', ' desinstalando um modulo objetivo desinstalar um modulo seu site deve estar no modo de manutencao quando voce desinstalar modulos veja ativando e desativando o modo de manutencao para mais detalhes passos no menu administrativo gerenciar  navegue ate estender   desinstalar  digite uma palavra do nome do modulo ou da descricao na caixa do filtro para tornar a lista de modulos menor localize o modulo que deseja desinstalar na coluna descricao  veja se ha razoes porque este modulo nao pode ser desinstalado por exemplo voce pode ter criado conteudo usando este modulo que voce precisaria excluir primeiro ou pode existir outro modulo instalado que exija que este modulo seja instalado voce precisaria desinstalar o outro modulo primeiro se nao houver razoes listadas o modulo pode ser desinstalado marque a caixa na coluna desinstalar  ao lado do nome do modulo clique em desinstalar na parte inferior da pagina verifique a lista de modulos a serem desinstalados e a configuracao a ser excluida na pagina de confirmacao e clique em desinstalar  aguarde que o modulo seja desinstalado voce deve ser redirecionado para a pagina desinstalar com uma mensagem dizendo que o modulo foi desinstalado  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (32, 'pt-br', 'help_search', ' gerenciando o indice de busca objetivo gerencie o indice de busca e certifiquese de que o site esta totalmente indexado para busca o que e o indice de busca  os tipos de pesquisa de conteudo e ajuda fornecidos pelo software principal preindexam seu conteudo e armazenam os resultados em varias tabelas de banco de dados que sao coletivamente chamadas de indice de pesquisa  o processo de indexacao renderiza o conteudo e divideo em palavras que podem ser combinadas de forma mais eficiente com consultas de palavraschave quando os usuarios realizam pesquisas a indexacao da pesquisa acontece durante as execucoes do cron veja executando e configurando o cron para obter mais informacoes sobre o cron passos no menu administrativo gerenciar  navegue ate configuracao   pesquisa e metadados   paginas de busca  em acelerador de indexacao  selecione o numero de itens para indexar por execucao do cron  um numero menor tornara o cron mais rapido e reduzira a possibilidade de tempo limite um numero maior garantira que mais do seu site seja indexado em menos execucoes do cron em configuracoes de indexacao padrao  digite o comprimento minimo da palavra para indexar desejado palavras menores que esse comprimento serao retiradas de ambas as palavraschave ao buscar e indexar conteudo se o seu site usa idiomas chines japones ou coreano opcionalmente marque o manuseio simples do cjk nas configuracoes de indexacao padrao para fornecer algum suporte para esses idiomas clique em salvar configuracao e voce deve ser redirecionado para a pagina paginas de busca  clique em reindexar o site se voce alterou a configuracao de indexacao ou mais tarde se voce acredita que o indice de busca foi corrompido siga os passos de executando e configurando o cron para garantir que uma tarefa de cron tenha sido configurada depois de esperar que o cron seja executado diversas vezes verifique se o conteudo foi totalmente indexado para busca o status geral e listado em progresso de indexacao e o status de cada pagina de busca e mostrado na coluna de progresso de indexacao da secao paginas de busca   ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (82, 'pt-br', 'help_search', ' adicionando formuario de operacoes em lote em uma view objetivo adicione uma ou mais acoes existentes como operacoes em massa em uma view de estilo de tabela existente se voce tiver o modulo actions ui do nucleo instalado consulte o topico relacionado configurando acoes para obter mais informacoes sobre acoes quem pode editar views  o modulo views ui do core precisara ser instalado e voce precisara da permissao administrar views para editar uma view passos no menu administrativo gerenciar  navegue ate estrutura   views  uma lista de todas as views e apresentada encontre a view que voce gostaria de editar e clique em editar no botao suspenso observe que as operacoes em massa funcionam melhor em uma view com display de pagina e um formato de tabela se ainda nao houver um formulario de operacoes em massa na lista de campos para a view clique em adicionar na secao campos para adicionalo o nome exato do campo de formulario operacoes em massa ira variar e pode conter palavraschave como atualizacao em massa elemento de formulario ou operacoes nao confundir com links de operacoes que sao aplicados a cada item em uma linha se o campo de operacoes em massa ja existir clique no nome de campo para editar suas configuracoes verifique as acoes que deseja disponibilizar na lista de acoes selecionadas e clique em aplicar todos os displays   verifique se as configuracoes de acesso para a view sao menos restritivas que as permissoes necessarias para executar as operacoes em massa pessoas com permissao para ver a view mas que nao tem permissao para fazer as operacoes em massa terao problemas clique em salvar  as acoes estarao disponiveis como operacoes em massa na view  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (41, 'pt-br', 'help_search', ' limpando o cache do site objetivo limpa os dados armazendos no cache do site o que e cache  alguns dos calculos que sao feitos quando seu site carrega uma pagina levam muito tempo para serem executados para economizar tempo quando esses calculos precisariam ser feitos novamente seus resultados podem ser armazenados em cache no banco de dados do seu site existem mecanismos internos para limpar dados armazenados em cache quando as condicoes ou suposicoes que entraram no calculo mudaram mas voce tambem pode limpar os dados armazenados manualmente quando seu site esta se comportando mal um bom primeiro passo e limpar o cache e ver se o problema desaparece passos no menu administrativo gerenciar  navegue ate configuracao    desenvolvimento performance  clique em limpar todos os caches  os dados do seu site armazenados em cache serao limpos recursos adicionais conceito cache guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (40, 'pt-br', 'help_search', ' instalando um modulo objetivo instale um modulo core ou um modulo contribuido que ja tenha sido baixado passos no menu administrativo gerenciar  navegue ate estender  digite uma palavra do nome do modulo ou da descricao na caixa do filtro para tornar a lista de modulos menor localize o modulo que deseja instalar marque a caixa ao lado do nome do modulo que deseja instalar voce tambem pode marcar mais de uma caixa para instalar varios modulos ao mesmo tempo se a caixa do modulo que voce esta tentando instalar estiver desativada expanda as informacoes para ver porque pode ser que voce precise baixar um modulo adicional que seu modulo precisa clique em instalar na parte inferior da pagina se voce optou por instalar um modulo com dependencias que ainda nao estavam instaladas ou se voce escolheu um modulo experimental confirme sua escolha na proxima pagina aguarde a instalacao do modulo ou modulos voce deve ser redirecionado para a pagina estender com uma mensagem dizendo que o modulo ou modulos foram instalados  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (46, 'pt-br', 'help_search', ' configurando como contas de usuarios sao criadas e deletadas objetivo define as configuracoes relacionadas de como as contas de usuarios sao criadas e excluidas quais sao as configuracoes relacionadas a criacao e exclusao de contas de usuario  voce pode deixar que novos usuarios se registrem com ou sem verificacao de email ou aprovacao administrativa ou voce dizer que apenas administradores com permissao de administrar usuarios possam registrar novos usuarios voce pode configurar o que acontece com o conteudo que um usuario criou se sua conta for cancelada  excluida voce pode editar as mensagens de email enviadas aos usuarios quando suas contas estao pendentes aprovadas criadas bloqueadas ou canceladas ou quando solicitam uma redefinicao de senha quais sao variaveis na mensagem do texto do email  variaveis sao strings de texto curtas incluidas entre colchetes que voce pode inserir no texto da mensagem de email configurada quando uma mensagem individual e gerada os dados do seu site sao substituidos pelas variaveis algumas variaveis comumente utilizadas sao site name o nome do seu site site url a url do seu site site loginurl a url onde os usuarios podem se autenticar no seu site user displayname o nome do usuario apresentado user accountname o nome da conta do usuario user mail o email alternativo do usuario user onetimeloginurl uma url temporaria que um usuario pode usar para fazer login uma vez se precisar recuperar sua senha passos no menu administrativo gerenciar  navegue ate configuracao   pessoas  opcoes da conta  selecione o metodo que deseja usar para criar contas de usuario e marque ou desmarque a caixa que requer verificacao de email para corresponder as configuracoes desejadas para o seu site selecione a opcao desejada para o que acontece com o conteudo que um usuario criou se sua conta for cancelada opcionalmente edite o texto das mensagens de email relacionadas as contas de usuarios verifique se as outras configuracoes estao corretas clique em salvar configuracao  voce deve ver uma mensagem indicando que as configuracoes foram salvas  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (43, 'pt-br', 'help_search', ' adicionando um novo papel objetivo criar um novo papel passos no menu administrativo gerenciar  navegue ate pessoas   papeis  clique em adicionar papel  digite o nome do papel desejado se quiser clique em editar para alterar o nome de maquina para o papel clique em salvar  voce deve ser redirecionado para a pagina papeis e seu novo papel deve estar na lista de papeis  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (7, 'pt-br', 'help_search', ' gerenciamento breakpoints de altura largura e resolucao o que sao breakpoints  breakpoints sao o ponto em que o conteudo do seu site respondera para fornecer ao usuario o melhor layout possivel para consumir as informacoes um breakpoint separa a altura ou largura das versoes telas impressoras e outros tipos de saida de midia em etapas por exemplo um breakpoint com largura de 40em cria duas etapas uma para larguras ate 40em e outra para larguras acima de 40em os breakpoints podem ser usados para definir quando os layouts devem mudar de uma forma para outra quando as imagens devem ser redimensionadas e outras alteracoes que precisam responder a alteracoes na altura ou largura do viewport o que sao consultas de midia  consultas de midia sao uma maneira formal de codificar breakpoints por exemplo um breakpoint de largura em 40em seria escrito como a consulta de midia minwidth 40em breakpoints sao realmente apenas consultas de midia com alguns metadados adicionais como informacoes de nome e multiplicador o que sao multiplicadores de resolucao  os multiplicadores de resolucao sao uma medida de resolucao de pontos de visualizacao do dispositivo definida para que seja a proporcao entre o tamanho fisico de pixel do dispositivo ativo e o tamanho do pixel independente de dispositivo  o modulo breakpoint define multiplicadores como 1 15 e 2 ao definir breakpoints modulos e temas podem definir quais multiplicadores se aplicam a cada breakpoint o que e um grupo de breakpoint  os breakpoints podem ser organizados em grupos modulos e temas devem usar grupos para separar os breakpoints que devem ser usados para diferentes propositos como breakpoints para layouts ou breakpoints para dimensionamento de imagem gerenciando breakpoints e previsualizacao de grupos de breakpoints o modulo breakpoint permite definir breakpoints e grupos de breakpoints em arquivos yaml modulos e temas podem usar a api fornecida pelo modulo breakpoint para definir breakpoints e grupos de breakpoints e atribuir multiplicadores de resolucao para breakpoints recursos adicionais trabalhando com breakpoints no drupal padroes w3c para consultas de midia ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (9, 'pt-br', 'help_search', ' importando sua configuracao completa do site objetivo importe a configuracao completa do seu site a partir de um arquivo de arquivo como um que foi exportado anteriormente ver exportando a configuracao completa do site consulte gerenciamento e implantacao de configuracao para obter mais informacoes sobre a configuracao passos no menu administrativo gerenciar  navegue ate configuracao   desenvolvimento   sincronizacao de configuracao   importar  navegue para encontrar o arquivo de configuracao que deseja importar clique em carregar  seu arquivo de configuracao sera descompactado e colocado no diretorio de sincronizacao de configuracao e voce sera redirecionado para a pagina sincronizar  revise as diferencas entre a configuracao do upload e a configuracao ativa se houver e clique em importar tudo para importar as alteracoes  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (38, 'pt-br', 'help_search', ' alterando as configuracoes basicas do site objetivo configure as definicoes do seu site incluindo o nome do site slogan email principal fuso horario padrao pais padrao e o formato de data a ser utilizado passos no menu administrativo gerenciar  navegue ate configuracao   sistema   configuracao basica do site  digite o nome do site slogan e o principal endereco de email do site clique em salvar configuracao  voce deve ver uma mensagem indicando que as configuracoes foram salvas no menu administrativo gerenciar  navegue ate configuracao   regiao e idioma   configuracoes regionais  selecione o pais e o fuso horario padrao para o seu site clique em salvar configuracao  voce deve ver uma mensagem indicando que as configuracoes foram salvas no menu administrativo gerenciar  navegue ate configuracao   regiao e idioma   formatos de data e hora  veja os padroes para os formatos padrao de data longa media e curta se algum deles nao corresponder ao formato de data que deseja usar em seu site clique em editar nessa linha para editar o formato ajuste a formatar string ate que o formato exibido corresponda ao que voce deseja as strings de formato de data sao compostas por codigos de formato de data php clique em salvar formato  voce deve ver uma mensagem indicando que o formato foi salvo repita as tres etapas anteriores para quaisquer outros formatos de data que precisem ser alterados recursos adicionais referencia de codigos de formato de data php ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (15, 'pt-br', 'help_search', ' otimizando o desempenho do site o que e desempenho do site  o desempenho do site neste contexto referese a fatores de velocidade como o tempo de carga da pagina e o tempo de resposta apos uma acao do usuario em uma pagina o que e cache  o cache esta economizando saida html ja renderizadas e outros dados calculados para uso posterior na primeira vez que e necessario isso economiza tempo porque da proxima vez que os mesmos dados sao necessarios eles podem ser rapidamente recuperados em vez de recalculados os sistemas de cache automatico tambem incluem mecanismos para excluir calculos em cache ou marcalos como nao mais validos quando os dados subjacentes mudam para facilitar isso os dados armazenados em cache possuem uma vida util  que e o tempo maximo antes que os dados sejam excluidos do cache forcando o recalculo  o que e agregacao de arquivos  agregacao e quando os arquivos css e javascript sao mesclados e compactados em um formato muito menor do que o original isso permite uma transmissao mais rapida e renderizacao mais rapida na outra extremidade o que posso fazer para melhorar o desempenho do meu site  os seguintes modulos do nucleo e mecanismos podem melhorar o desempenho do seu site modulo internal page cache armazena paginas solicitadas por usuarios que nao estao autenticados usuarios anonimos nao use esta opcao se o seu site precisa enviar saidas diferentes para diferentes usuarios anonimos modulo internal dynamic page cache cache dados para usuarios autenticados e anonimos com dados nao armazenados na pagina convertidos em espacos reservados e calculados quando a pagina e solicitada modulo big pipe altera a forma como as paginas sao enviadas aos usuarios de modo que as partes em cache sao enviadas primeiro com espacos reservados e as partes da pagina nao cacheadas ou personalizadas sao transmitidas posteriormente isso permite que o navegador renderize a maior parte da pagina rapidamente e preencha os detalhes mais tarde configuracoes de pagina de desempenho no menu administrativo gerenciar  se voce navegar para configuracoes   desenvolvimento   desempenho  voce encontrara uma configuracao para a idade maxima do cache bem como a opcao de ativar a agregacao de arquivos css e javascript recursos adicionais documentacao online para o modulo interno page cache documentacao online para o modulo interno dynamic page cache documentacao online para o modulo bigpipe ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (79, 'pt-br', 'help_search', ' gerenciamento listagens de conteudo views  o que e uma view  uma view e uma lista de itens em seu site por exemplo um bloco mostrando os comentarios mais recentes uma pagina listando itens de noticias ou uma lista de usuarios registrados as listagens podem ser formatadas em uma tabela grade lista calendario feed rss e outros formatos alguns formatos de saida podem exigir que voce instale modulos adicionais contribuidos  quais sao os componentes de uma view  quando voce criar uma view pela primeira vez voce especificara que tipo de dadosbase estao sendo apresentados na view que nao pode ser alterado depois de escolher um tipo de dadosbase voce pode editar os seguintes componentes que permitem a voce especificar quais dados serao apresentados em qual ordem e em qual formato  displays  se a saida vai para uma pagina bloco feed etc uma unica view pode ter varios displays cada um com configuracoes diferentes formato  o estilo de saida para cada exibicao como item de conteudo grade tabela ou lista html fields  se o formato permitir os campos especificos para exibir criterios de filtro  criterios para limitar os dados de saida como o conteudo e publicado o tipo de conteudo etc filtros podem ser expostos para permitir que usuarios escolham como filtrar os dados criterios de classificacao  como classificar os dados a classificacao tambem pode ser exposta para os usuarios configuracoes da pagina   configuracoes de bloco  etc configuracoes especificas do tipo de exibicao como a url para uma exibicao de pagina a maioria dos tipos de exibicao suporta uma configuracao de acesso onde voce pode escolher uma permissao ou papel que um usuario deve ter para ver a view cabecalho e rodape  conteudo para ser exibido na parte superior ou inferior da exibicao da view comportamento sem resultados  o que fazer se os criterios do filtro nao resultarem em dados para exibir paginador  quantos itens exibir e como paginalos se houverem itens adicionais para exibir avancados   filtros contextuais  igual filtros regulares exceto que os criterios vem do contexto  como a data atual a pagina em que a view e exibida etc avancado   relacionamentos  dados adicionais para puxar e exibir relacionados de alguma forma aos dados basicos da view como dados do usuario que criou o item de conteudo  avancado   formulario exposto  se voce tiver filtros expostos ou classificacoes como exibir o formulario para o usuario o que sao operacoes em lote  views que usam um formato de exibicao de tabela podem incluir um formulario de operacoes em massa que permite que os usuarios com permissao suficiente selecionem um ou mais itens da view e apliquem uma acao administrativa a eles as acoes em massa disponiveis sao especificas para o tipo de dados base da view por exemplo uma view de itens de conteudo pode dar suporte a acoes de publicacao e cancelamento de publicacao em massa se voce tiver o modulo actions ui do nucleo instalado consulte o topico relacionado configurando acoes para obter mais informacoes sobre acoes visao geral de views o modulo views do core lida com a exibicao de views e o modulo views ui do core permite que voce crie edite e exclua views na interface administrativa consulte os topicos relacionados listados abaixo para tarefas especificas se o modulo views ui estiver instalado  recursos adicionais criando listagens com views guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (48, 'pt-br', 'help_search', ' gerenciando contas de usuarios e visitantes do site o que e um usuario  usuario e qualquer pessoa acessando ou visitando seu site usuarios anonimos sao usuarios que nao estao logados e usuarios autenticados sao usuarios que estao logados o que e um papel  papeis sao usados para agrupar e classificar usuarios cada usuario ter um ou mais papeis existem tambem papeis especiais para todos os usuarios anonimos e autenticados o que e uma permissao  a concessao de uma permissao para um papel permite que os usuarios que foram designados para desempenhar esse papel executem uma acao no site como ver conteudo editar ou criar um determinado tipo de conteudo administrar configuracoes para um determinado modulo ou usar uma funcao especifica do site como a busca  visao geral do gerenciamento de contas e visitantes the core user module allows users to register log in and log out and administrators to manage user roles and permissions depending on which modules you have installed on your site the related topics below will help you with tasks related to managing user accounts and visitors  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (61, 'pt-br', 'help_search', ' configurando deteccao e selecao de idiomas objetivo configure os metodos usados para decidir qual idioma sera usado para exibir texto em seu site o que e um metodo de deteccao de idiomas  um metodo de deteccao de idioma e uma maneira de seu site decidir qual idioma deve ser usado para exibir texto esta decisao e tomada avaliando uma serie de metodos de deteccao para idiomas o primeiro metodo de deteccao que obtem um resultado determinara qual idioma e usado se voce tiver mais de um idioma em seu site voce pode configurar os metodos de deteccao que sao usados e a ordem que eles sao avaliados tanto para texto da interface do usuario quanto para texto de conteudo o texto de configuracao sempre usa o metodo de texto da interface e a maioria dos sites usa os mesmos metodos de deteccao para todos os tipos de texto quais metodos de deteccao de idiomas estao disponiveis  os metodos de deteccao disponiveis dependem de quais modulos estao instalados alguns dos metodos de deteccao de idiomas mais usados sao url use o idioma a partir da url que pode estar em um prefixo de caminho como exemplocom br pagepath para o idioma portugues br ou em um dominio como brexemplocom pagepath  usuario para usuarios conectados use o idioma que eles definiram em seus perfis navegador use as preferencias de idioma do navegador do usuario idioma selecionado use o idioma mais recentemente selecionado a partir de um bloco de alternancia de idiomas  sessao use o idioma a partir de um parametro de sessao ou de um parametro de solicitacao por exemplo adicionando  language br ao final da url passos no menu administrativo gerenciar  navegue ate configuracao   regiao e idioma   idiomas  deteccao e selecao marque as caixas dos metodos de deteccao de idiomas desejados e desmarque as caixas para os metodos que voce nao deseja usar se quiser arraste os metodos para mudar sua ordem clique em salvar configuracoes  clique em configurar em cada metodo de deteccao ativado e verifique se as configuracoes estao correta ou atualizeas  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (12, 'pt-br', 'help_search', ' connecting text editors to text formats objetivo configure um formato de texto para que quando um usuario estiver editando texto e selecione esse formato de texto um editor de texto instalado em seu site seja mostrado configure o editor de texto como escolher quais botoes e funcoes estao disponiveis consulte gerenciando filtros e formatos de texto para saber mais sobre formatos de texto o que e um editor de texto  um editor de texto e um software normalmente uma biblioteca javascript que fornece botoes e outros mecanismos de comando para facilitar a edicao de texto html alguns editores sao chamados de editores visuais ou wysiwyg what you see is what you get  esses editores ocultam os detalhes html do usuario e em vez disso mostram a saida formatada na tela o modulo core text editor fornece uma estrutura para implantar editores de texto em seu site o modulo do core ckeditor 5 fornece o ckeditor 5 que e um editor de texto javascript amplamente utilizado que cria html limpo e valido o modulo tambem impoe restricoes de tags html no formato de texto associado varios modulos contribuidos fornecem outros editores para instalar um novo editor alem de instalar o modulo talvez seja necessario baixar a biblioteca do editor de um site de terceiros passos no menu administrativo gerenciar  navegue ate configuracao criacao de conteudo   formatos e editores de texto  a coluna editor de texto na tabela mostra o editor de texto que esta atualmente conectado a cada formato de texto se houver siga as etapas gerenciando filtros e formatos de texto para adicionar um novo formato de texto ou configurar um formato de texto existente quando voce chegar ao passo sobre editores de texto retorne a este topico selecione ckeditor 5 como o editor de texto ou outro editor de texto que voce instalou o restante dessas etapas pressupoe que voce selecionou ckeditor 5  em configuracao da barra de ferramentas  arraste os botoes entre botoes disponiveis e barra de ferramentas ativa  somente os botoes na barra de ferramentas ativa serao mostrados para o usuario focar ou passar o mouse sobre um botao exibira uma dica de ferramenta explicando o que o botao faz arraste botoes dentro da barra de ferramentas ativa para a ordem desejada e agrupe botoes arrastandoos entre identificadores de grupo arraste um novo identificador de grupo para a barra de ferramentas para adicionar grupos adicionais se voce adicionar botoes que exijam configuracao a secao configuracoes do plugin ckeditor 5 ficara visivel e fornecera seus respectivos formularios de configuracao retorne ao gerenciando filtros e formatos de texto para concluir a configuracao do formato de texto e nao se esqueca de salvar o formato de texto  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (72, 'pt-br', 'help_search', ' editando um item de conteudo objetivo encontre um item de conteudo e editeo ou atualize um grupo de itens de conteudo em massa consulte gerenciando conteudo para saber mais sobre tipos de conteudo e itens de conteudo quem pode procurar e editar conteudo  usuarios com permissao de acessar a pagina de visao geral de conteudo podem usar a pagina conteudo para encontrar conteudo cada tipo de conteudo tem suas proprias permissoes de edicao por exemplo para editar o conteudo do tipo artigo um usuario precisaria da permissao artigo editar o proprio conteudo para editar um artigo que criou ou a permissao artigo editar qualquer conteudo para editar um artigo que outra pessoa criou alem disso usuarios com as permissoes de pular o controle de acesso de conteudo e administrar conteudo podem editar itens de conteudo de todos os tipos alguns modulos contribuidos alteram a estrutura de permissao para edicao de conteudo passos no menu administrativo gerenciar  navegue ate conteudo  opcionalmente use filtros para reduzir a lista de itens de conteudo mostrados  titulo  palavrachave s do titulo tipo de conteudo status de publicacao idioma se voce digitar ou selecionar valores de filtro clique em filtro para aplicar os filtros opcionalmente classifique a lista clicando em um cabecalho de coluna clique novamente para reverter a ordem para editar o titulo ou outros valores de campo para um item de conteudo clique em editar na linha do item de conteudo atualize os valores e clique em salvar  alguns tipos de edicoes podem ser feitas em massa para varios itens de conteudo por exemplo para publicar varios itens de conteudo nao publicados marque as caixas na coluna esquerda coluna direita em idiomas da direita para a esquerda para selecionar os itens de conteudo desejados para acao  selecione a acao publicar conteudo  clique em aplicar nos itens selecionados para fazer a alteracao as outras acoes em acao funcionam de forma semelhante recursos adicionais gerenciamento basico de paginas guia do usuario do drupal  editando um item de conteudo guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (78, 'pt-br', 'help_search', ' configurando taxonomia objetivo crie um vocabulario de taxonomia e adicione um campo de referencia para esse vocabulario a uma entidade de conteudo consulte gerenciando taxonomia para obter informacoes sobre taxonomias e gerenciando estrutura de conteudo sobre entidades de conteudo quem pode configurar um vocabulario de taxonomia  usuarios com permissao de administrar vocabularios e termos podem configurar um vocabulario para adicionar um campo na interface administrativa o modulo field ui do core deve ser instalado e voce tambem precisara da permissao de administrar campos para a entidade a qual voce esta adicionando o campo passos no menu administrativo gerenciar  navegue ate estrutura   taxonomia  clique em adicionar vocabulario  no campo nome  digite um nome para o vocabulario por exemplo ingredientes que e como ele sera mostrado na interface administrativa opcionalmente adicione uma descricao clique em salvar  seu vocabulario sera criado e voce vera a pagina que lista todos os termos deste vocabulario opcionalmente clique em adicionar termo para adicionar um termo ao novo vocabulario no campo nome  digite o nome do termo por exemplo manteiga clique em salvar  voce recebera uma confirmacao sobre o termo que criou voce pode opcionalmente continuar a adicionar mais termos se voce tiver o modulo field ui do core instalado siga as instrucoes existentes em adicionando um campo de referencia a um subtipo de entidade para adicionar um campo de referencia de taxonomia ao tipo de entidade de sua escolha a pagina de configuracoes permitira que voce escolha o vocabulario que voce criou como vocabulario para referencia voce pode tambem desejar configurar a exibicao e formulario de exibicao do novo campo ver topicos relacionados  recursos adicionais configurando uma taxonomia guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (24, 'pt-br', 'help_search', ' trabalhando com idiomas e traducoes que texto pode ser traduzido em seu site  existem tres tipos de texto que podem ser traduzidos o conteudo blocos itens de conteudo etc pode ser escrito em ingles ou em outro idioma e pode ser traduzido para idiomas adicionais veja gerenciando estrutura de conteudo para saber mais sobre conteudo muitos itens de configuracao tambem incluem texto que pode ser traduzido a configuracao padrao fornecida pelo software do seu site e fornecida em ingles voce tambem pode baixar traducoes fornecidas pela comunidade veja gerenciamento e implantacao de configuracao para saber mais sobre configuracao o texto da interface do usuario que e fornecido pelo software principal seu perfil de instalacao temas e modulos sao fornecidos em ingles mas podem ser traduzidos para outros idiomas voce tambem pode baixar traducoes que os membros da comunidade desenvolveram trabalhando com visao geral de idiomas the core language module lets you add new languages to your site provides the language switcher block and provides the ability to configure block visibility by language the block and block visibility settings are only available if you have multiple languages configured the core content translation configuration translation and interface translation modules let you translate content configuration and the builtin user interface respectively the core locale module manages automatic downloads of communityprovided translations of default configuration and userinterface text if the core update status module is installed see the related topics listed below for specific tasks  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (57, 'pt-br', 'help_search', ' adicionando um campo a um subtipo de entidade objetivo adicionar um campo a um subtipo de entidade consulte gerenciando estrutura de conteudo para uma visao geral dos tipos de entidades e subtipos bem como uma visao geral dos tipos de campo passos navegue ate a pagina para gerenciar o subtipo de entidade ao qual voce deseja adicionar o campo por exemplo para adicionar um campo a um tipo de conteudo no menu administrativo gerenciar  navegue ate estrutura   tipos de conteudo  encontre o subtipo especifico para qual deseja adicionar o campo e clique em gerenciar campos  clique adicionar campo  em adicionar um novo campo  selecione o tipo de campo que deseja adicionar consulte gerenciando estrutura de conteudo para uma visao geral dos tipos de campo o campo rotulo agora deve ser visivel digite um rotulo para o campo que e usado como rotulo de campo para edicao e exibicao de conteudo clique em salvar e continuar  na proxima tela digite um valor para o numero de valores permitidos  voce pode limitar o campo a um valor por item de entidade um numero definido de valores ou definilo para ter valores ilimitados clique em salvar configuracoes de campo  na proxima tela opcionalmente edite as configuracoes para o campo que variam de acordo com o tipo de campo que voce esta criando para todos os campos voce pode editar o rotulo  o texto de ajuda  texto exibido abaixo do campo na pagina de edicao do conteudo e campo obrigatorio  para forcar que um valor seja digitado para salvar o conteudo ao editar voce tambem pode configurar um valor padrao para o campo clique em salvar configuracoes  voce deve ser redirecionado para a pagina gerenciar campos  com seu novo campo na lista  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (81, 'pt-br', 'help_search', ' adicionando um novo display a uma view existente objetivo adiciona um novo display em uma view existente isso permite que voce exiba dados semelhantes em uma view existente usando configuracoes semelhantes em um novo bloco pagina feed etc passos se voce ainda nao estiver editando sua exibicao no menu administrativo gerenciar  navegue ate estrutura  views  localize a vista que voce deseja editar e clique no link editar  em displays  clique em adicionar  na lista popup clique no link para o tipo de exibicao que deseja adicionar os tipos mais comuns sao pagina e bloco  o novo display sera adicionado a sua exibicao e voce estara editando esse display opcionalmente clique no link proximo do nome do display e digite um novo nome para este display na interface administrativa siga os passos de editando um display de view existente para editar as outras configuracoes do display  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (77, 'pt-br', 'help_search', ' gerenciando taxonomia o que e uma taxonomia  taxonomia e usada para classificar o conteudo do site um exemplo comum de taxonomia sao as tags usadas para classificar ou categorizar posts em um site de blog um site de culinaria poderia usar uma taxonomia de ingredientes para classificar receitas os itens individuais de taxonomia sao conhecidos como termos  as tags do blog ou ingredientes de receita nesses exemplos e um conjunto de termos e conhecido como vocabulario  o conjunto de todas as tags de postagem do blog ou o conjunto de todos os ingredientes da receita nesses exemplos tecnicamente os termos da taxonomia sao um tipo entidade e os subtipos da entidade sao os vocabularios veja gerenciando estrutura de conteudo para mais informacoes sobre entidades de conteudo como outras entidades os termos de taxonomia podem ter campos anexados por exemplo voce pode configurar um campo de imagem para conter um icone para cada termo um vocabulario individual pode organizar seus termos em uma hierarquia ou pode ser plano por exemplo as tags de blog normalmente tem uma estrutura plana enquanto um vocabulario de ingredientes de receita pode ser hierarquico por exemplo tomates podem ser um subtermo de vegetais e sob tomates voce poderia ter tomates verdes e vermelhos os termos da taxonomia sao normalmente anexados como campos de referencia para outras entidades de conteudo que e como voce pode usalos para classificar o conteudo quando voce configura um campo de referencia de taxonomia voce pode permitir que os usuarios digitem termos de duas maneiras marcacao livre novos termos podem ser criados diretamente no formulario de edicao de conteudo lista fixa de termos a lista de termos e curada e gerenciada fora do formulario de edicao de conteudo e usuarios ao editar conteudo so podem selecionar termos da lista existente os campos de referencia de taxonomia podem ser adicionados a qualquer entidade como contas de usuario blocos de conteudo ou itens de conteudo regulares se voce usalos para classificar itens de conteudo regulares seu site sera configurado automaticamente com paginas de listagem de taxonomia para cada termo cada uma dessas paginas lista todos os itens de conteudo classificados com esse termo visao geral do gerenciamento de taxonomia o modulo taxonomy do core permite que voce crie e edite vocabularios de taxonomia e termos de taxonomia o modulo field ui do core fornece uma interface de usuario para adicionar campos a entidades incluindo o campo de referencia de taxonomia e configurar a edicao e exibicao de campo veja os topicos relacionados listados abaixo para tarefas especificas recursos adicionais conceito taxonomia guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (25, 'pt-br', 'help_search', ' usando a edicao de configuracoes em linha rapida  objetivo edite as configuracoes no local o que e edicao rapida  o modulo principal settings tray fornece capacidade de editar rapidamente as configuracoes em linha ele requer o modulo principal contextual links para expor os links que permitem editar no local quem pode editar as configuracoes no local  para seguir estas etapas para editar as configuracoes no local o modulo principal settings tray deve estar instalado alem disso o modulo principal toolbar ou um modulo substituto da comunidade deve ser instalado voce precisa ter a permissao usar links contextuais  bem como a permissao para editar o conteudo ou as configuracoes especificas passos encontre e visite uma pagina em seu site que tenha as configuracoes que voce gostaria de editar clique no botao editar dos links contextuais na barra de ferramentas na maioria dos temas parece um lapis  editar contextual links com o mesmo icone aparecera por toda a pagina encontre o link contextual para a parte da pagina que deseja editar por exemplo se voce quiser editar as configuracoes de um bloco o link deve estar no canto superior direito do bloco ou no canto superior esquerdo para idiomas da direita para a esquerda clique no link para abrir o menu de links contextuais e clique em edicao rapida  um formulario de edicao para as configuracoes deve aparecer na pagina faca suas edicoes e envie o formulario  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (30, 'pt-br', 'help_search', ' habilitando web services o que e um web service  um servico web permite que seu site forneca seu conteudo e dados para outros sites e aplicativos normalmente os dados sao transportados via http em um formato serializado de leitura de maquina o que e serializacao  serializacao e o processo de conversao de estruturas de dados complexas em cadeias de texto para que possam ser trocadas e armazenadas o processo inverso e chamado de deserializacao  json e xml sao os dois formatos de serializacao de dados mais usados para servicos web o que e autenticacao basica http  autenticacao basica http e um metodo para autenticar solicitacoes enviando um nome de usuario e senha junto com a solicitacao quais modulos fornecem servicos web  os seguintes modulos do nucleo fornecem web services modulo json api expoe entidades a outros aplicativos usando uma implementacao totalmente compativel da especificacao json api  consulte gerenciando estrutura de conteudo para obter mais informacoes sobre entidades de conteudo e campos modulo restful web services expoe entidades e outros recursos para outros aplicativos usando uma implementacao rest  os dados sao trocados usando um formato de serializacao como json e transferidos usando um metodo de autenticacao como a autenticacao basica http modulo serialization fornece uma estrutura para adicionar formatos de serializacao especificos para outros modulos usarem modulo http basic authentication fornece uma maneira para web services serem autenticados usando a autenticacao http basic em contas de usuario do site tambem existem modulos contribuidos que fornecem servicos web recursos adicionais documentacao online para o modulo restful web services documentacao online para o modulo json api comparacao dos modulos restful web services e json api ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (21, 'pt-br', 'help_search', ' mantendo e solucionando problemas em seu site visao geral de manutencao e solucao de problemas aqui estao algumas tarefas e dicas relacionadas a manutencao do seu site e solucao de problemas que podem surgir em seu site veja os topicos relacionados abaixo para mais informacoes ao realizar manutencao como instalar desinstalar ou atualizar um modulo coloque seu site no modo de manutencao configure seu site para que o cron seja executado periodicamente se o seu site nao estiver se comportando como esperado limpe o cache antes de tentar diagnosticar o problema no site existem varios relatorios que podem ajudalo a diagnosticar problemas ha tambem dois modulos do core que podem ser usados para registro de erros database logging e syslog recursos adicionais prevenindo e corrigindo problemas guia do usuario do drupal  seguranca e manutencao guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (3, 'pt-br', 'help_search', ' gerenciando blocos o que sao blocos  os blocos sao caixas de conteudo renderizadas em uma area ou regiao de uma pagina web do seu site os blocos sao posicionados e configurados especificamente para cada tema o que sao blocos de conteudo  os blocos de conteudo sao blocos cujo conteudo voce pode editar voce pode definir um ou mais tipos de bloco e anexar campos a cada tipo de bloco os blocos de conteudo podem ser colocados da mesma forma que os blocos fornecidos por outros modulos o que e a descricao de bloco  a descricao do bloco e um nome de identificacao para um bloco que e mostrado na interface administrativa nao e exibida no site qual e o titulo do bloco  o titulo do bloco e o titulo que e mostrado opcionalmente aos visitantes quando o bloco e colocado em uma regiao visao geral para gerenciamento de blocos o modulo block permite que voce coloque blocos em regioes de seus temas instalados e defina as configuracoes de bloco o modulo block content permite gerenciar tipos de blocos e blocos de conteudo consulte os topicos relacionados listados abaixo para tarefas especificas recursos adicionais blocos guia do usuario do drupal  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (17, 'pt-br', 'help_search', ' acessibilidade da interface administrativa visao geral de acessibilidade a interface administrativa principal tem conformidade incorporada com muitos padroes de acessibilidade para que a maioria das paginas sejam acessiveis em seu estado padrao a maioria dos usuarios no entanto certas paginas se tornam mais acessiveis para alguns usuarios atraves do uso de uma interface nao padrao ou melhorada essas interfaces incluem desativando a funcionalidade arrastar e soltar a interface padrao de arrastaresoltar de usuario para ordenar tabelas na interface administrativa representa um desafio para alguns usuarios incluindo usuarios que usam somente teclado e usuarios de leitores de tela e outras tecnologias assistivas a interface arrastaresoltar pode ser desativada em uma tabela clicando em um link rotulado mostrar pesos na linha acima da tabela a interface de substituicao permite que usuarios ordenem a tabela escolhendo pesos numericos com numeros crescentes em vez de arrastar linhas da tabela habilitando erros de formularios inline erros que ocorrem quando voce envia um formulario como nao preencher um campo necessario as vezes sao dificeis para os usuarios entenderem e localizarem para tornar esses erros mais faceis de serem encontrados a melhor pratica e colocar um resumo dos erros na parte superior da pagina do formulario para tornalos mais faceis de entender a melhor pratica e exibir mensagens de erro com os campos de formulario a que estao relacionados ambas as praticas sao implementadas pelo modulo core inline form errors  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (28, 'pt-br', 'help_search', ' alterando a aparencia de seu site o que e um tema  um tema e um conjunto de arquivos que definem a aparencia visual do seu site o core e os modulos habilitados em seu site determinam qual conteudo incluindo texto html e outros dados armazenados no banco de dados imagens carregadas e quaisquer outros arquivos ou ativos sao exibidos nas paginas do seu site o tema determina a marcacao html e o estilo css que envolve o conteudo varios temas basicos sao fornecidos com o core temas contribuidos adicionais podem ser baixados separadamente na pagina download estender no drupalorg  ou voce pode criar seu proprio tema o que e um tema base  um tema base e um tema que nao se destina a ser usado diretamente em um site mas atua como um andaime para a construcao de outros temas o tema do core stable 9 e um exemplo outros temas basicos podem ser baixados na pagina download extend no drupalorg  o que e um layout  um layout e um modelo que define onde blocos e outras pecas de conteudo devem ser exibidos o modulo do core layout discovery permite que modulos e temas registrem layouts e o modulo core layout builder fornece uma interface visual para colocar campos e blocos em layouts para subtipos de entidades e itens de entidades individuais veja gerenciando estrutura de conteudo para mais sobre entidades e campos  previsualizar a alteracao da aparencia do site a principal maneira de alterar a aparencia geral do seu site e alternar o tema padrao os modulos principais layout builder e layout discovery permitem que voce defina layouts para o conteudo do seu site e o modulo principal breakpoint ajuda os temas para alterar a aparencia em dispositivos de tamanhos diferentes consulte os topicos relacionados listados abaixo para tarefas especificas recursos adicionais extendendo e customizando seu site guia do usuario do drupal  temas drupal ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (37, 'pt-br', 'help_search', ' executando relatorios em seu site objetivo execute relatorios para saber sobre o estado e a saude do seu site passos no menu administrativo gerenciar  navegue ate relatorios   relatorio de status para ver um relatorio que resume a integridade e o status do seu site se houver algum aviso ou erro voce precisara corrigilo atentese a todas proximas versoes de seguranca altamente criticas que podem afetar seu site se voce tiver o modulo database logging do core instalado no menu administrativo gerenciar  navegue ate relatorios   mensagens recentes do registro para ver um relatorio de erros e das mensagens informacionais geradas pelo seu site voce pode filtrar o relatorio por gravidade para ver apenas as mensagens mais criticas se desejar if you have the core update status module installed in the manage administrative menu navigate to reports   available updates to see a report of the updates that are available for your site software if last checked is far in the past click check manually to update the report scan the report if the core software or any modules or themes have security updates available you should update them as soon as possible recursos adicionais seguranca e manutencao guia do usuario do drupal  que inclui informacoes sobre como atualizar o nucleo modulos e temas do seu site  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (20, 'pt-br', 'help_search', ' trabalhando com topicos de ajuda o que e um topico de ajuda  um topico de ajuda descreve um conceito ou etapas para realizar uma tarefa relacionado a um recurso fornecido por um ou mais modulos ou temas se o modulo search do nucleo estiver ativado esses topicos tambem poderao ser pesquisados onde estao listados os topicos de ajuda  os topicos de ajuda de nivel superior estao listados em ajuda links para outros topicos incluindo topicos de ajuda que nao sao de nivel superior podem ser encontrados sob o titulo relacionado ao visualizar uma pagina de topico como os topicos de ajuda sao providos  modulos e temas podem fornecer topicos de ajuda como plugins baseados em arquivos twig em um subdiretorio do projeto chamado helptopics  os metadados do plugin sao fornecidos via sintaxe yaml em cada arquivo twig os topicos de ajuda baseados em plugins fornecidos por modulos e temas serao atualizados automaticamente quando um modulo ou tema for atualizado use os plugins em core modules help helptopics como um guia ao escrever e formatar um plugin de topico de ajuda para seu tema ou modulo como os topicos de ajuda sao traduzidos  o titulo e o corpo do texto dos topicos de ajuda fornecidos pelos modulos e temas contribuidos podem ser traduzidos usando traducao da interface do usuario fornecido pelo modulo interface translation os topicos fornecidos por modulos e temas personalizados tambem podem ser traduzidos se tiverem sido visualizados pelo menos uma vez em um idioma diferente do ingles o que aciona a colocacao de seu texto traduzivel no banco de dados de traducao como os usuarios podem pesquisar topicos de ajuda  para permitir que os usuarios pesquisem ajuda incluindo topicos de ajuda voce precisara instalar o modulo search do nucleo configurar uma pagina de pesquisa e adicionar um bloco de pesquisa a pagina de ajuda ou a outra pagina administrativa uma pagina de pesquisa e fornecida automaticamente e se voce usar o tema administrativo claro um bloco de pesquisa de ajuda sera mostrado na pagina principal da ajuda em seguida os usuarios com permissoes de pesquisa e permissao para exibir a ajuda poderao pesquisar ajuda consulte o topico relacionado configurando busca da ajuda para obter instrucoes passo a passo recursos adicionais topicos de ajuda padrao ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (33, 'pt-br', 'help_search', ' configurando a busca do site o que sao paginas de busca  o modulo search do core organiza a busca do site em paginas  cada pagina permite que usuarios busquem um determinado tipo de conteudo com uma configuracao especifica a configuracao inclui informar uma url que comeca com busca  um nome para a pagina e opcoes adicionais para alguns tipos de pagina de busca quando os usuarios visitam a pagina de pesquisa principal consulte buscar  eles verao as paginas de pesquisa configuradas as quais tem acesso cada pagina de pesquisa tem um formulario de pesquisa e a pagina exibira os resultados da pesquisa depois que o usuario inserir palavraschave no formulario e clicar no botao de pesquisa quais modulos fornecem busca no site  o modulo search do core fornece a capacidade de configurar paginas de busca os tipos de pagina de busca sao fornecidas por modulos do core e contribuidos os modulos do core que fornecem tipos de pagina de busca sao o modulo node para buscar paginas de conteudo o modulo user para buscar perfis de usuarios o modulo help para buscar topicos de ajuda como uma alternativa ao sistema de paginas de busca do modulo do core search voce pode usar modulos contribuidos para fornecer buscas no site por exemplo os modulos contribuidos apache solr e sphinx usam tecnologia de terceiros para fornecer buscas no site quais sao as limitacoes do modulo core search  existem duas limitacoes principais do modulo search do core primeiro ele nao e apropriado para sites muito grandes se voce tem um site grande olhe para outras tecnologias de busca como apache solr em segundo lugar o tipo de pagina de busca node so suporta correspondencia exata de palavraschave que nao e o comportamento que a maioria dos usuarios espera voce pode melhorar isso instalando um modulo especifico para seu idioma como porter stemmer para ingles americano o que faz com que por exemplo uma busca pela palavra caminhada corresponda as paginas que contem as palavras caminhar caminham e caminharam quais sao as permissoes de busca  usuarios com permissao de usar busca podem usar o bloco de formulario de busca e a pagina busca  esta permissao e necessaria para qualquer busca configurada no modulo core search adicionalmente a usar busca  a permissao ver informacoes do usuario e necessaria para buscar usuarios adicionalmente a usar busca  a permissao ver conteudo publicado e necessaria para buscar conteudo os usuarios com permissao de usar pesquisa avancada podem usar filtros de busca mais complexos quando realizarem buscas de conteudo configurando a visao geral da busca do site in order to configure site search using the core search module you will need to configure one or more search pages you will also need to verify or alter permissions so that the desired user roles can search the site see gerenciando contas de usuarios e visitantes do site for more information about roles and permissions for content search you will also need to make sure that the search index is configured and that the site is fully indexed finally you may wish to place the search form block on pages of your site or add the search page to a navigation menu to give users easy access to search see the related topics listed below for specific tasks recursos adicionais documentacao online para o modulo de pesquisa ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (1, 'pt-br', 'help_search', ' visualizando anuncios do drupal o que sao os anuncios do drupal  um feed de anuncios sobre o projeto drupal e os programas da drupal association o objetivo desse feed e fornecer um canal de divulgacao diretamente para os proprietarios de sites do drupal este conteudo deve ser altamente relevante para os interesses dos proprietarios do site servir os objetivos estrategicos do projeto e ou promover a sustentabilidade do projeto e da drupal association o modulo obtem seu conteudo de um feed json gerado a partir daqui  a politica de governanca para o conteudo esta documentada aqui  como eu posso ver os anuncions em meu site  se voce tiver o modulo toolbar ativado vera um link direto para eles na barra de ferramentas se o modulo toolbar nao estiver habilitado o conteudo sempre podera ser acessado na pagina announcements  quem pode ver os anuncios  os usuarios com a permissao veja os anuncios oficiais relacionados ao drupal podem visualizar os anuncios do drupal recursos adicionais visao geral do modulo announcement ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (76, 'pt-br', 'help_search', ' criando e utilizando atalhos de links administrativos objetivo crie veja e use um conjunto de atalhos para acessar paginas administrativas o que sao atalhos  atalhos sao links rapidos para paginas administrativas eles sao gerenciados pelo modulo shortcut do core um site pode ter um ou mais conjuntos de atalhos que podem ser compartilhados por um ou mais usuarios por padrao ha apenas um conjunto compartilhado por todos os usuarios cada conjunto contem um numero limitado de atalhos os usuarios precisam ter a permissao de usar atalhos para ver atalhos a permissao editar o conjunto de atalhos atuais para adicionar excluir ou editar os atalhos no conjunto atribuido a eles e a permissao selecionar qualquer conjunto de atalho para selecionar um conjunto de atalho diferente ao editar seu perfil de usuario ha tambem uma permissao de administrar atalhos que permite que um administrador faca qualquer uma dessas acoes bem como selecione conjuntos de atalhos para outros usuarios passos certifiquese de que o modulo shortcut esteja instalado e que voce tenha um papel com a permissao editar conjunto de atalhos atual ou administrar atalhos  alem disso certifiquese de que um modulo da barra de ferramentas esteja instalado o modulo toolbar do nucleo ou um modulo contribuido substituto navegue ate uma pagina administrativa que voce deseja em sua lista de atalhos clique no link de atalho para adicionar a pagina a sua lista de atalhos no tema administrativo claro do core o link se parece com uma estrela e e exibido ao lado do titulo da pagina no entanto se a pagina ja estiver no seu conjunto de atalhos clicar no link de atalho ira removela do seu conjunto de atalhos repita ate que todos os links desejados sejam adicionados ao conjunto de atalhos clique em atalhos na barra de ferramentas para exibir seus atalhos e verifique se a lista esta completa opcionalmente clique em editar atalhos na extremidade direita da lista de atalhos para remover links ou alterar sua ordem clique em qualquer link na barra de atalho para ir diretamente a pagina administrativa  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (5, 'pt-br', 'help_search', ' definindo um tipo de bloco objetivo defina um tipo de bloco e seus campos passos no menu administrativo gerenciar  navegue ate estrutura   tipos de bloco  clique em adicionar tipo de bloco  digite um rotulo para este tipo de bloco mostrado na interface administrativa opcionalmente edite o nome de maquina gerado automaticamente ou a descricao clique em salvar  voce sera redirecionado para a pagina tipos de bloco  clique em gerenciar campos na linha do seu novo tipo de bloco e adicione os campos desejados ao seu tipo de bloco opcionalmente clique em gerenciar a exibicao de formulario ou em gerenciar exibicao para alterar o formulario de edicao ou exibicao de campo para seu tipo de bloco  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (18, 'pt-br', 'help_search', ' configurando busca da ajuda objetivo configure seu site para os usuarios poderem buscar por ajuda passos no menu administrativo gerenciar  navegue ate estender  verifique se os modulos search help e block estao instalados ou instaleos se ainda nao estiverem instalados no menu administrativo gerenciar  navegue ate configuracoes   busca e metadados   paginas de busca  verifique se uma pagina de busca de ajuda esta listada na secao paginas de busca  se nao adicione uma nova pagina do tipo ajuda  verifique o status de indexacao da pagina de pesquisa ajuda se nao estiver totalmente indexado veja executando e configurando o cron sobre como executar o cron ate que a indexacao esteja concluida no futuro voce pode clicar em reconstruir o indice de pesquisa nesta pagina ou limpando o cache do site a fim de forcar o texto de ajuda de topico a ser reindexado para pesquisa isso deve ser feito sempre que um modulo tema idioma ou traducao de string for atualizado no menu administrativo gerenciar  navegue ate estrutura   layout de bloco  clique no link para o seu tema administrativo como o tema claro do core proximo a parte superior da pagina e verifique se ja ha um bloco de pesquisa para ajuda localizado na regiao ajuda caso contrario siga as etapas no topico relacionado para colocar o bloco de formulario de pesquisa na regiao ajuda ao configurar o bloco escolha ajuda como a pagina de pesquisa e na guia paginas em visibilidade  digite  admin help para tornar o formulario de pesquisa visivel apenas na pagina principal de ajuda  no menu administrativo gerenciar  navegue ate ajuda  verifique se o bloco de pesquisa esta visivel e tente uma pesquisa  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (64, 'pt-br', 'help_search', ' importando um arquivo de traducao objetivo importe um arquivo extensaopo contendo traducoes para texto da interface do usuario passos no menu administrativo gerenciar  navegue ate configuracao   regiao e idioma   traducao da interface do usuario  importar navegue para encontrar o arquivo de traducao que deseja importar selecione o idioma e marque as opcoes de importacao desejadas clique em importar e aguarde que seu arquivo seja importado  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (55, 'pt-br', 'help_search', ' adicionando um campo de referencia para um subtipo de entidade objetivo adicionar um campo de referencia de entidade a um subtipo de entidade consulte gerenciando estrutura de conteudo para obter mais informacoes sobre entidades e campos de referencia passos navegue ate a pagina para gerenciar o subtipo de entidade ao qual voce deseja adicionar o campo por exemplo para adicionar um campo a um tipo de conteudo no menu administrativo gerenciar  navegue ate estrutura   tipos de conteudo  encontre o subtipo especifico para qual deseja adicionar o campo e clique em gerenciar campos  clique adicionar campo  em adicionar um novo campo  selecione o tipo de campo de referencia que deseja adicionar a secao referencia da lista selecionada mostra os tipos mais comuns de campo de referencia escolha outro  se o tipo de entidade que voce deseja fazer referencia nao estiver listado o campo rotulo agora deve ser visivel digite um rotulo para o campo que e usado como rotulo de campo para edicao e exibicao de conteudo clique em salvar e continuar  na proxima tela verifique se o tipo de entidade que voce deseja referenciar e mostrado no tipo de item para referencia ou caso contrario selecione isto digite um valor para o numero de valores permitidos  voce pode limitar o campo para um valor por item de entidade um numero definido de valores ou definilo para ter valores ilimitados clique em salvar configuracoes de campo  na tela seguinte opcionalmente edite as configuracoes para rotulo   texto de ajuda  texto a ser exibido abaixo do campo na pagina de edicao de conteudo e campo obrigatorio  para que um valor seja digitado para salvar o conteudo durante a edicao na secao tipo de referencia  voce geralmente deseja limitar os subtipos da entidade que podem ser referenciados por exemplo se voce estiver criando uma referencia de conteudo  voce pode marcar uma ou duas opcoes de tipo de conteudo  as escolhas serao ainda mais faceis para os editores de conteudo procurarem se voce tambem escolher um valor de classificacao normalmente o titulo da entidade ou o campo de rotulos clique em salvar configuracoes  voce deve ser redirecionado para a pagina gerenciar campos  com seu novo campo na lista  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (27, 'pt-br', 'help_search', ' tornando seu site seguro o que sao atualizacoes de seguranca  qualquer software ocasionalmente tem bugs e as vezes esses bugs tem implicacoes de seguranca quando os bugs de seguranca sao corrigidos no software principal modulos ou temas que seu site usa sao liberados em uma atualizacao de seguranca  voce precisara aplicar atualizacoes de seguranca para manter seu site seguro o que sao avisos de seguranca  um comunicado de seguranca e um anuncio publico sobre um problema de seguranca relatado no software principal os projetos contribuidos com um icone de escudo e versoes estaveis para este projeto sao cobertas pela politica de consultoria de seguranca na pagina do projeto tambem sao cobertos pela politica de consultoria de seguranca do drupal os avisos de seguranca sao gerenciados pela equipe de seguranca do drupal  tarefas de seguranca acompanhar as atualizacoes atualizar o software principal e atualizar modulos e ou temas contribuidos fazem parte de manter seu site seguro veja os topicos relacionados listados abaixo para tarefas especificas recursos adicionais seguranca e manutencao guia do usuario do drupal  processo de consultoria de seguranca e politica de permissoes ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (23, 'pt-br', 'help_search', ' gerenciamento de midia o que sao itens de midia  os principais itens de midia do core incluem audio imagens documentos e videos voce pode adicionar outros tipos de midia como postagens em redes sociais atraves do uso de modulos contribuidos os itens de midia podem ser arquivos localizados no sistema de arquivos do seu site ou itens remotos referenciados por uma url os itens de midia sao entidades de conteudo e sao divididos em tipos de midia que sao subtipos de entidades tipos de midia podem ter campos consulte gerenciando estrutura de conteudo para obter mais informacoes sobre entidades e campos de conteudo o que e a biblioteca de midia  a biblioteca de midia e uma interface visual do usuario para gerenciar e reutilizar itens de midia adicione itens de midia ao conteudo usando campos de referencia de midia e o widget de campo da biblioteca de midia o que e um estilo de imagem  um estilo de imagem e um conjunto de etapas de processamento conhecidos como efeitos  que podem ser aplicados as imagens exemplos de efeitos incluem dimensionamento e corte de imagens para diferentes tamanhos estilos de imagem responsivos podem associar estilos de imagem aos breakpoints de tamanho do seu tema isso permite fornecer imagens dimensionadas para a largura do navegador visao geral da gestao de midia os seguintes modulos fornecem funcionalidade relacionada a midia itens de midia e tipos de midia sao gerenciados pelo modulo media o modulo media do core fornece um campo de referencia de midia para adicionar midia a entidades de conteudo os modulos file e image do core tambem fornecem campos de referencia recomendase usar o campo de referencia media porque e mais versatil o modulo media library do core fornece a biblioteca de midia e o widget de campo da biblioteca de midia com este modulo instalado o widget de campo da biblioteca de midia tornase o widget padrao para editar campos de referencia de midia o modulo image do core fornece uma interface de usuario para definir estilos de imagem o modulo responsive image do core fornece estilos de imagem responsivas usando o modulo breakpoint do core e um tema habilitado para breakpoint esses estilos responsivos podem fornecer imagens dimensionadas para o navegador consulte os topicos relacionados listados abaixo para tarefas especificas recursos adicionais modulo media ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (56, 'pt-br', 'help_search', ' configurando a exibicao de campos para um subtipo de entidade objetivo configure os formatadores usados para exibir os campos de um subtipo de entidade sua ordem no display e as configuracoes de formatacao consulte gerenciando estrutura de conteudo para obter mais informacoes passos navegue ate a pagina para gerenciar o tipo de entidade ao qual voce deseja adicionar o campo por exemplo para adicionar um campo a um tipo de conteudo no menu administrativo gerenciar  navegue ate estrutura   tipos de conteudo  encontre o subtipo especifico do qual deseja configurar o display e clique em exibir na lista operacoes  use as setas de arrasto para ordenar os campos na ordem que deseja arraste todos os campos que voce nao deseja ver no display para a secao desativar  na coluna rotulo  selecione a posicao para cada etiqueta de campo na exibicao ou  oculto  para ocultar um rotulo voce tambem pode escolher  visualmente escondido  se voce quiser que o texto da etiqueta apareca na pagina html para que os leitores de tela e mecanismos de busca possam lelo mas sem mostralo na coluna formato  selecione o formatador para exibir cada campo depois de selecionar os formatadores desejados clique na engrenagem de configuracoes em cada linha para alterar as configuracoes do formatador quando terminar de fazer alteracoes clique em salvar  teste a apresentacao para o subtipo de entidade visualizando sua entidade se necessario retorne a essas etapas para refinar ainda mais a apresentacao  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (58, 'pt-br', 'help_search', ' configurando o formulario de edicao para um subtipo de entidade objetivo configure os widgets usados para editar os campos de um subtipo de entidade sua ordem no formulario e as configuracoes do widget consulte gerenciando estrutura de conteudo para obter mais informacoes passos navegue ate a pagina para gerenciar o tipo de entidade ao qual voce deseja adicionar o campo por exemplo para adicionar um campo a um tipo de conteudo no menu administrativo gerenciar  navegue ate estrutura   tipos de conteudo  encontre o subtipo especifico para o qual deseja configurar o formulario de edicao e clique em exibir formulario na lista operacoes  use as setas de arrasto para ordenar os campos na ordem que deseja arraste todos os campos que voce nao deseja ver no formulario de edicao para a secao desativar  na coluna widget  selecione o widget para editar cada campo depois de selecionar os widgets desejados clique na engrenagem de configuracoes em cada linha para alterar as configuracoes do widget quando terminar de fazer alteracoes clique em salvar  teste o formulario de edicao para o subtipo da sua entidade editando ou criando uma entidade se necessario retorne a essas etapas para refinar ainda mais o formulario  ', 1773421629);
INSERT INTO public.drupal_search_dataset (sid, langcode, type, data, reindex) VALUES (8, 'pt-br', 'help_search', ' importando um unico item de configuracao objetivo importe um unico item de configuracao em formato yaml como aquele que foi exportado anteriormente ver exportando um unico item de configuracao consulte gerenciamento e implantacao de configuracao para obter mais informacoes sobre a configuracao passos no menu administrativo gerenciar  navegue ate configuracao   desenvolvimento   sincronizacao de configuracao   importar   item unico  selecione o tipo de configuracao que deseja importar no seu computador ou outro dispositivo copie para a area de transferencia a configuracao em formato yaml que deseja importar cole o texto da area de transferencia na caixa cole aqui sua configuracao  clique em importar   ', 1773421629);
